LANG_DATA['bo'].meta = { family:'Sino-Tibetan (Tibeto-Burman, Bodish)', speakers:'~6M', speakerBasis:'L1', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'bod', countries:'China (Tibet), India, Nepal', official:'Tibet Autonomous Region (co-official)', script:'Tibetan', description:{en:'Tibetan script preserves archaic spelling reflecting Classical Tibetan pronunciation. Spoken across the Tibetan Plateau and Himalayan regions. Lhasa Central Tibetan is the de facto standard with a binary HIGH/LOW tone system derived from written initials (Audit Task 146 source-checked rebuild).'}, sources:[{type:'reference', title:'Tournadre & Sangda Dorje — Manual of Standard Tibetan'},{type:'reference', title:'Wiktionary Lhasa Tibetan IPA conventions', url:'https://en.wiktionary.org/wiki/Wiktionary:Tibetan_transliteration'},{type:'reference', title:'Ethnologue 27: Tibetan', url:'https://www.ethnologue.com/language/bod/'}] };
