// Caribbean Javanese — Suriname Javanese diaspora.
LANG_DATA['jvn'].meta = { family:'Austronesian (Malayo-Polynesian, Javanese, diaspora)', speakers:'~60K', countries:'Suriname, Netherlands (Javanese-Surinamese diaspora)', official:'Suriname (recognized regional)', script:'Latin', description:{en:'Caribbean Javanese (Bahasa Jawa Suriname) is the Javanese language as spoken by the Javanese-Surinamese community, descendants of indentured workers brought from Dutch East Indies (now Indonesia) to Suriname between 1890 and 1939 (~33,000 contracted, with most settling permanently). The variety has diverged from standard Java-Java Javanese (jv) through 130+ years of isolation: extensive Sranan Tongo and Dutch loanwords, simplified speech-level (krama-ngoko) system, and some Suriname-specific vocabulary. Recognized as one of Suriname\'s major heritage languages.'}, sources:[{type:'reference', title:'Glottolog: Caribbean Javanese', url:'https://glottolog.org/resource/languoid/id/cari1280'}, {type:'reference', title:'Ethnologue: jvn', url:'https://www.ethnologue.com/language/jvn/'}, {type:'reference', title:'Vruggink (1990) Caribbean Javanese', url:'https://www.kitlv.nl/'}], scriptTags:['Latin'], parentCode:'jv' };
