LANG_DATA['km'].meta = { family:'Austroasiatic', speakers:'~16M', speakerBasis:'L1', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'khm', countries:'Cambodia', official:'Cambodia', script:'Khmer', description:{en:'Khmer is non-tonal, unlike its neighbors, and has one of the largest alphabets in the world. Inscriptions date to the 7th century. IPA rebuilt per Audit Task 146 to remove romanization-style forms (preah/mae/snaehaː/beh/pteah) — Phnom Penh standard.'}, sources:[{type:'reference', title:'Headley (1977) — Cambodian-English Dictionary'},{type:'reference', title:'Wiktionary Khmer IPA conventions', url:'https://en.wiktionary.org/wiki/Wiktionary:Khmer_transliteration'},{type:'reference', title:'Ethnologue 27: Khmer', url:'https://www.ethnologue.com/language/khm/'}] };
