// Rangpuri (Kamtapuri) — Indo-Aryan Eastern, ~15M.
LANG_DATA['rkt'].meta = { family:'Indo-European (Indo-Aryan, Eastern, Bengali-Assamese)', speakers:'~15M', countries:'Bangladesh (Rangpur Division), India (West Bengal — Cooch Behar; Assam — Goalpara)', official:'No (Bangladesh recognizes Bangla/Bengali only); West Bengal recognized in some districts', script:'Bengali / Latin', description:{en:'Rangpuri (also Kamtapuri or Rajbanshi) is an Eastern Indo-Aryan language between Bengali (bn) and Assamese (as), with ~15M speakers in NW Bangladesh, West Bengal, and lower Assam. Long classified as a Bengali dialect for political reasons; Glottolog and modern Indian census now treat it as a separate language. The historical Koch-Kamta kingdom (16th-19th c.) was its political-cultural anchor.'}, sources:[{type:'reference', title:'Glottolog: Rangpuri', url:'https://glottolog.org/resource/languoid/id/rang1265'}, {type:'reference', title:'Ethnologue: rkt', url:'https://www.ethnologue.com/language/rkt/'}, {type:'reference', title:'Wilde (2008) Sociolinguistic Survey of Rangpuri', url:'https://www.sil.org/'}], scriptTags:['Bengali','Latin'] };
