LANG_DATA['jpr'].meta = { family:'Indo-European (Iranian, Western, Persian Jewish)', speakers:'~60K', countries:'Iran (Isfahan, Shiraz, Tehran historically), Israel, USA (NYC), Europe diaspora', official:'No (Hebrew/Arabic in IL; Persian in Iran); recognized minority heritage', script:'Hebrew (with vowel pointing for vernacular use)', description:{en:'Judeo-Persian (Pārsi yahudi) is a cluster of Persian dialects historically spoken by Iranian Jewish communities, written in Hebrew script. Includes literary varieties from medieval Persia (Bukhori in Central Asia is a sister Tajik-Persian variety, treated separately as bhh). The post-1948 emigration of most Iranian Jews to Israel (~250K total) and the 1979 Islamic Revolution further reduced the Iran-resident population to ~60K of the original ~140K. Hebrew script transmission preserved many archaic Persian features lost in Persian-script writing.'}, sources:[{type:'reference', title:'Glottolog: Judeo-Persian', url:'https://glottolog.org/resource/languoid/id/jude1257'}, {type:'reference', title:'Ethnologue: jpr', url:'https://www.ethnologue.com/language/jpr/'}, {type:'reference', title:'Lazard (1968) La langue des plus anciens monuments de la prose persane', url:'https://www.persee.fr/'}], scriptTags:['Hebrew'] };
