LANG_DATA['azb'] && (LANG_DATA['azb'].meta = { family:'Turkic (Oghuz, Azerbaijani)', speakers:'~13–15M', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'azb', countries:'Iran (East/West Azerbaijan, Ardabil, Zanjan)', official:'No (recognized minority)', script:'Perso-Arabic (Iranian convention); Latin online', description:{en:'South Azerbaijani is the Oghuz Turkic of northwestern Iran, where Iranian Azerbaijanis are the largest minority. Distinct from the Republic of Azerbaijan standard (Latin script, less Persian influence) — Iranian Azerbaijani uses Perso-Arabic script and shares much vocabulary with Persian.'} });
