LANG_DATA['lij'].meta = { family:'Romance (Gallo-Italic)', speakers:'~500K', countries:'Italy (Liguria), Mediterranean diaspora (Monaco, Argentina)', official:'No (recognized regional)', script:'Latin (with æ ô)', description:'Ligurian (Lìgure) is a Gallo-Italic Romance language spoken in northwestern Italy and Mediterranean diaspora communities. The Genoese standard has historical importance as the language of the Republic of Genoa. Distinctive nasalised vowels and final-vowel reduction.', sources:[{type:'reference', title:'Glottolog: Ligurian', url:'https://glottolog.org/resource/languoid/id/ligu1248'}, {type:'reference', title:'Ethnologue: lij', url:'https://www.ethnologue.com/language/lij/'}] };
