LANG_DATA['li'].meta = { family:'Indo-European (Germanic, West)', speakers:'~1.3M', countries:'Netherlands (Limburg), Belgium (Limburg), Germany (Lower Rhine)', official:'Netherlands (recognized regional)', script:'Latin', description:'Limburgish (Limburgs) is a West Germanic dialect cluster spoken in the Limburg-Lower Rhine border region. Distinctively for a Germanic variety, it has contrastive pitch accent (Stoßton vs. Schleifton) similar to Norwegian/Swedish — likely contact-induced from Frankish substratum. The Netherlands recognized it under European Charter Part II in 1997.', sources:[{type:'reference', title:'Glottolog: Limburgish', url:'https://glottolog.org/resource/languoid/id/limb1263'}, {type:'reference', title:'Ethnologue: lim', url:'https://www.ethnologue.com/language/lim/'}] };
