LANG_DATA['sma'] && (LANG_DATA['sma'].meta = { family:'Uralic (Saami, Western)', speakers:'~500–600', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'sma', countries:'Norway (Trøndelag–Nordland), Sweden (Jämtland–Härjedalen)', official:'Recognized minority language (Norway, Sweden)', script:'Latin (Southern Sámi orthography, 1978)', description:{en:'Southern Sámi is the most divergent surviving Sámi language. It is not mutually intelligible with Northern Sámi, has a richer vowel system, and is critically endangered — concentrated in central Norway and Sweden along the Trøndelag–Jämtland border.'} });
