LANG_DATA['tzo'].meta = { family:'Mayan (Cholan-Tseltalan)', speakers:'~430K', countries:'Mexico (Chiapas)', official:'Mexico (national)', script:'Latin', description:{en:'Tzotzil (Bats\'i k\'op) is a Mayan language native to the highlands of Chiapas. The pre-Hispanic name "Bats\'i k\'op" means "true language." It is closely related to Tzeltal, with which it forms the Tzeltalan branch.'} };
// Audit Task 141: Tzeltal — Mayan sister to Tzotzil
LANG_DATA['tzh'] && (LANG_DATA['tzh'].meta = { family:'Mayan (Cholan-Tseltalan)', speakers:'~600K', speakerBasis:'L1', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'tzh', countries:'Mexico (Chiapas)', official:'Mexico (national)', script:'Latin', description:{en:'Tzeltal (Bats\'il k\'op, "true language") is a Mayan language of highland Chiapas, sister to Tzotzil within the Tzeltalan branch. The largest Mayan language by L1 speakers in Mexico after Yucatec.'}, sources:[{type:'reference', title:'Ethnologue 27: Tzeltal', url:'https://www.ethnologue.com/language/tzh/'}], parentCode:'tzo', varietyRole:'sibling-language' });
LANG_DATA['mix'].meta = { family:'Oto-Manguean (Mixtecan)', speakers:'~500K (macrolanguage)', countries:'Mexico (Oaxaca, Guerrero, Puebla)', official:'Mexico (national)', script:'Latin', description:{en:'Mixtec (Tu\'un Sávi, "rain language") is a complex of dozens of varieties, often mutually unintelligible, spoken across the Mixteca region of southern Mexico. All varieties are tonal, with up to four phonemic tones.'} };
LANG_DATA['zap'].meta = { family:'Oto-Manguean (Zapotecan)', speakers:'~440K (macrolanguage)', countries:'Mexico (Oaxaca)', official:'Mexico (national)', script:'Latin', description:{en:'Zapotec (Diidxazá in the Isthmus variety) is another Oto-Manguean language complex of southern Mexico. The Zapotec civilization developed one of Mesoamerica\'s earliest writing systems around 500 BCE; modern varieties are tonal.'} };
LANG_DATA['ay'].meta = { family:'Aymaran', speakers:'~2M', countries:'Bolivia, Peru, Chile', official:'Bolivia, Peru', script:'Latin', description:{en:'Aymara is the principal language of the Aymara people, centered around Lake Titicaca. It is one of three official languages of Bolivia and is famous for its evidential markers (whether the speaker witnessed an event) and its ternary numeral system.'} };
// Asháninka — Arawakan (Kampan), largest Arawakan in Peru, ~25K-50K speakers.
// Shuar — Jivaroan, ~35K, Ecuadorian + Peruvian Amazon. Famous historically for tsantsa.
LANG_DATA['jiv'].meta = { family:'Jivaroan', speakers:'~35K', countries:'Ecuador (Morona Santiago, Pastaza, Zamora Chinchipe), Peru (north)', official:'Ecuador (recognized indigenous, co-official with Spanish in Shuar territory; one of 14 indigenous nationality languages)', script:'Latin', description:{en:'Shuar (Shuar Chicham) is the principal Jivaroan language, spoken by the Shuar people of Ecuadorian and Peruvian Amazon. Historically infamous in Western anthropology for the tsantsa (shrunken-head) practice — a now-discontinued mortuary ritual that was extensively misrepresented in 19th-20th century travel literature. The Shuar Federation (1964) was a pioneering indigenous rights organization. Closely related to Awajún (Aguaruna) and Achuar within the Jivaroan family. Active intergenerational use; bilingual education programs in Spanish and Shuar across Ecuador.',ja:'シュアル語（Shuar Chicham）はジバロ語派の主要な言語で、エクアドル・ペルーのアマゾンのシュアル人によって話される。歴史的に欧米人類学では tsantsa（縮頭）の慣習で悪名高く、現在は廃止されたこの葬礼儀式は19〜20世紀の旅行文学で大いに誤って表現されてきた。シュアル連合（1964年）は先住民権利運動の先駆的組織。ジバロ語派内ではアワフン語（アグアルナ語）およびアチュアル語と近縁。世代間で活発に使用されており、エクアドル全土でスペイン語とシュアル語のバイリンガル教育プログラムが実施されている。',ko:'슈아르어(Shuar Chicham)는 지바로어파의 주요 언어로, 에콰도르와 페루의 아마존 슈아르 사람들이 사용한다. 역사적으로 서구 인류학에서는 tsantsa(축소머리) 관행으로 악명이 높았으며, 현재는 폐지된 이 장례 의식은 19-20세기 여행 문학에서 광범위하게 왜곡되어 표현되었다. 슈아르 연맹(1964)은 선구적인 원주민 권리 단체였다. 지바로어파 내에서 아와훈어(아과루나어) 및 아추아르어와 가까운 친족 관계이다. 세대 간 활발한 사용; 에콰도르 전역에서 스페인어와 슈아르어 이중 언어 교육 프로그램이 운영된다.',zh:'舒阿尔语（Shuar Chicham）是希瓦罗语支的主要语言，由厄瓜多尔和秘鲁亚马孙的舒阿尔人使用。在西方人类学中历史上以 tsantsa（缩头）习俗著称，这一已停止的丧葬仪式在 19-20 世纪的旅行文学中被广泛误传。舒阿尔联合会（1964）是先驱性的原住民权利组织。在希瓦罗语支内与阿瓦洪语（阿瓜鲁纳语）和阿丘阿尔语关系密切。世代间活跃使用；厄瓜多尔全国推行西班牙语和舒阿尔语双语教育项目。',vi:'Tiếng Shuar (Shuar Chicham) là ngôn ngữ Jivaroan chính, được người Shuar ở vùng Amazon Ecuador và Peru sử dụng. Trong nhân học phương Tây, từng nổi tiếng (và bị xuyên tạc) qua tập tục tsantsa (đầu thu nhỏ) — một nghi lễ tang chế đã chấm dứt nhưng được trình bày sai lệch trong văn học du ký thế kỷ 19-20. Liên đoàn Shuar (1964) là tổ chức đấu tranh quyền lợi bản địa tiên phong. Gần gũi với Awajún (Aguaruna) và Achuar trong họ Jivaroan. Vẫn được truyền giữa các thế hệ; chương trình giáo dục song ngữ tiếng Tây Ban Nha và Shuar phổ biến tại Ecuador.',de:'Shuar (Shuar Chicham) ist die wichtigste Jivaro-Sprache, gesprochen von den Shuar im ecuadorianischen und peruanischen Amazonas. Berüchtigt in der westlichen Anthropologie durch die Tsantsa-Praxis (Schrumpfköpfe) — ein heute eingestellter Bestattungsritus, der in der Reiseliteratur des 19./20. Jahrhunderts vielfach verzerrt dargestellt wurde. Die Shuar-Föderation (1964) war eine Pionierorganisation für indigene Rechte. Innerhalb der Jivaro-Familie eng verwandt mit Awajún (Aguaruna) und Achuar. Generationsübergreifend lebendig; in Ecuador landesweit zweisprachige Bildungsprogramme in Spanisch und Shuar.',fr:'Le shuar (Shuar Chicham) est la principale langue jivaro, parlée par les Shuar de l\'Amazonie équatorienne et péruvienne. Connue dans l\'anthropologie occidentale, à tort, par la pratique du tsantsa (têtes réduites) — un rituel funéraire désormais abandonné, largement déformé dans la littérature de voyage des XIXe et XXe siècles. La Fédération Shuar (1964) fut une organisation pionnière des droits autochtones. Au sein de la famille jivaro, étroitement apparentée à l\'awajún (aguaruna) et à l\'achuar. Transmise activement entre générations; programmes d\'éducation bilingue espagnol-shuar dans toute l\'Équateur.'}, sources:[{type:'reference', title:'Glottolog: Shuar', url:'https://glottolog.org/resource/languoid/id/shua1257'}, {type:'reference', title:'Ethnologue: jiv', url:'https://www.ethnologue.com/language/jiv/'}, {type:'reference', title:'Pellizzaro & Náwech (2005) Chicham. Diccionario shuar-castellano', url:'https://www.dineib.gob.ec/'}] };
LANG_DATA['cni'].meta = { family:'Arawakan (Southern, Kampan)', speakers:'~25K-50K', countries:'Peru (Junín, Pasco, Ucayali departments), Brazil (Acre)', official:'Peru (recognized indigenous, co-official with Spanish in Asháninka territory)', script:'Latin', description:{en:'Asháninka is the largest Arawakan language of Peru and one of the principal indigenous languages of the Peruvian Amazon. The Asháninka people, with their characteristic kushma robes, are one of the most populous Amazonian indigenous groups. Like other Arawakan languages, it has cross-referencing pronominal affixes and noun-classifier morphology. Survived massacres during the Sendero Luminoso conflict (1980s-90s) and remains in active intergenerational use.',ja:'アシャニンカ語はペルー最大のアラワク諸語の言語であり、ペルー・アマゾンの主要な土着言語の一つ。アシャニンカ人は特徴的なクシュマ衣装で知られ、最も人口の多いアマゾン先住民集団の一つである。他のアラワク諸語と同様、双方参照する代名詞接辞と名詞分類辞形態を持つ。センデロ・ルミノソ紛争（1980-90年代）の虐殺を生き延び、現在も世代間で活発に使用されている。',ko:'아샤닌카어는 페루 최대의 아라와크어이며 페루 아마존의 주요 토착어 중 하나이다. 아샤닌카 사람들은 특징적인 쿠슈마 의복으로 알려져 있으며 가장 인구가 많은 아마존 원주민 집단 중 하나이다. 다른 아라와크어와 마찬가지로 상호참조적 대명사 접사와 명사 분류사 형태를 가진다. 센데로 루미노소 분쟁(1980-90년대)의 학살에서 살아남았으며 현재도 세대 간에 활발히 사용된다.',zh:'阿沙宁卡语是秘鲁最大的阿拉瓦克语，是秘鲁亚马孙地区的主要土著语言之一。阿沙宁卡人以独特的库什玛长袍著称，是亚马孙最人口众多的原住民群体之一。与其他阿拉瓦克语一样，具有交叉参照的代词词缀和名词分类语素形态。在 1980-90 年代光辉道路游击战的屠杀中幸存，至今仍在世代间活跃使用。',vi:'Tiếng Asháninka là ngôn ngữ Arawak lớn nhất của Peru và là một trong các ngôn ngữ bản địa chính của vùng Amazon Peru. Người Asháninka, với áo choàng kushma đặc trưng, là một trong những nhóm bản địa Amazon đông dân nhất. Giống các ngôn ngữ Arawak khác, có phụ tố đại từ tham chiếu chéo và hình thái phân loại danh từ. Sống sót qua các cuộc thảm sát thời xung đột Sendero Luminoso (1980-90) và vẫn được sử dụng tích cực giữa các thế hệ.',de:'Asháninka ist die größte Arawak-Sprache Perus und eine der wichtigsten indigenen Sprachen des peruanischen Amazonas. Die Asháninka mit ihrem charakteristischen Kushma-Gewand sind eine der bevölkerungsreichsten indigenen Gruppen Amazoniens. Wie andere Arawak-Sprachen besitzt sie pronominale Querverweis-Affixe und eine Nominalklassifikatoren-Morphologie. Überlebte die Massaker während des Sendero-Luminoso-Konflikts (1980er–90er) und ist weiterhin generationsübergreifend in Gebrauch.',fr:'L\'asháninka est la plus grande langue arawak du Pérou et l\'une des principales langues autochtones de l\'Amazonie péruvienne. Les Asháninka, reconnaissables à leur cushma, sont l\'un des groupes autochtones les plus nombreux de l\'Amazonie. Comme les autres langues arawak, elle possède des affixes pronominaux à référence croisée et une morphologie à classificateurs nominaux. A survécu aux massacres du conflit du Sentier lumineux (années 1980-90) et reste activement transmise entre générations.'}, sources:[{type:'reference', title:'Glottolog: Asháninka', url:'https://glottolog.org/resource/languoid/id/asha1243'}, {type:'reference', title:'Ethnologue: cni', url:'https://www.ethnologue.com/language/cni/'}, {type:'reference', title:'Mihas (2010) Essentials of Asháninka grammar', url:'https://www.degruyter.com/'}] };
// Páez (Nasa Yuwe) — language isolate of Cauca Colombia, tonal, ~60K speakers.
LANG_DATA['pbb'].meta = { family:'Language isolate (sometimes grouped as Paezan)', speakers:'~60K', countries:'Colombia (Cauca, Huila, Tolima, Valle del Cauca)', official:'Colombia (recognized indigenous, co-official within Nasa territory)', script:'Latin (with apostrophe \' for ejection, ç for /ç/)', description:{en:'Páez (Nasa Yuwe, "language of the people") is the language of the Nasa people of southwestern Colombia, traditionally classified as a language isolate (the proposed Paezan family grouping it with neighboring isolates is contested). Tonal with ejective consonants and a complex aspectual verb system. The Nasa community runs Colombia\'s largest indigenous-led education and political movement (CRIC, founded 1971), and Nasa Yuwe is taught in over 100 community schools. Recognised internationally for the Nasa\'s sustained nonviolent resistance to displacement during Colombia\'s armed conflict.',ja:'パエス語（Nasa Yuwe、「人々の言葉」の意）はコロンビア南西部のナサ人の言語であり、伝統的に言語孤立として分類される（隣接する孤立語と一括するパエサン語族の提案は係争中）。声調と放出音、複雑な相動詞体系を持つ。ナサ共同体はコロンビア最大の先住民主導の教育・政治運動（CRIC、1971年設立）を運営し、ナサ・ユウェ語は100以上の共同体学校で教えられている。コロンビア武装紛争中の強制移住に対するナサの持続的非暴力抵抗で国際的に知られる。',ko:'파에스어(Nasa Yuwe, "사람들의 언어"의 뜻)는 콜롬비아 남서부 나사 사람들의 언어이며 전통적으로 언어 고립체로 분류된다(인접 고립어들과 묶는 파에스 어족 제안은 논쟁 중). 성조와 방출음, 복잡한 상 동사 체계를 가진다. 나사 공동체는 콜롬비아 최대의 원주민 주도 교육·정치 운동(CRIC, 1971년 설립)을 운영하며, 나사 유웨어는 100개 이상의 공동체 학교에서 가르쳐진다. 콜롬비아 무력 분쟁 중 강제 이주에 대한 나사의 지속적 비폭력 저항으로 국제적으로 알려져 있다.',zh:'帕埃斯语（Nasa Yuwe，意为"人民的语言"）是哥伦比亚西南部纳萨人的语言，传统上被归类为孤立语（将其与邻近孤立语并入的"帕埃斯语系"提议存在争议）。具有声调、挤喉音和复杂的体动词系统。纳萨社区运营着哥伦比亚最大的原住民主导的教育与政治运动（CRIC，1971 年成立），纳萨语在 100 多所社区学校中教授。以纳萨人在哥伦比亚武装冲突中持续的非暴力抗议位移而在国际上知名。',vi:'Tiếng Páez (Nasa Yuwe, "ngôn ngữ của người dân") là ngôn ngữ của người Nasa ở tây-nam Colombia, theo truyền thống được phân loại là ngôn ngữ cô lập (đề xuất ghép vào họ Paezan với các ngôn ngữ cô lập lân cận đang gây tranh cãi). Có thanh điệu, phụ âm phun bật hơi và hệ thống động từ chỉ thể phức tạp. Cộng đồng Nasa điều hành phong trào giáo dục và chính trị do người bản địa lãnh đạo lớn nhất Colombia (CRIC, thành lập 1971), tiếng Nasa được giảng dạy tại hơn 100 trường cộng đồng. Nổi tiếng quốc tế vì cuộc kháng nghị bất bạo động liên tục của người Nasa trong xung đột vũ trang Colombia.',de:'Páez (Nasa Yuwe, „Sprache der Menschen") ist die Sprache der Nasa im Südwesten Kolumbiens, traditionell als isolierte Sprache klassifiziert (der Vorschlag einer paezanischen Familie mit benachbarten Isolaten ist umstritten). Tonal mit ejektiven Konsonanten und einem komplexen Aspekt-Verbsystem. Die Nasa-Gemeinschaft betreibt Kolumbiens größte indigen geführte Bildungs- und politische Bewegung (CRIC, gegründet 1971); Nasa Yuwe wird an über 100 Gemeindeschulen unterrichtet. International bekannt durch die anhaltenden gewaltfreien Proteste der Nasa im kolumbianischen Bewaffneten Konflikt.',fr:'Le páez (Nasa Yuwe, « langue du peuple ») est la langue des Nasa du sud-ouest de la Colombie, traditionnellement classée comme isolat (la famille paezane proposée avec les isolats voisins est contestée). Tonal avec consonnes éjectives et un système verbal aspectuel complexe. La communauté nasa anime le plus grand mouvement éducatif et politique dirigé par des autochtones de Colombie (CRIC, fondé en 1971); le nasa yuwe est enseigné dans plus de 100 écoles communautaires. Reconnue internationalement pour la résistance non-violente persistante des Nasa dans le conflit armé colombien.'}, sources:[{type:'reference', title:'Glottolog: Páez', url:'https://glottolog.org/resource/languoid/id/paez1247'}, {type:'reference', title:'Ethnologue: pbb', url:'https://www.ethnologue.com/language/pbb/'}, {type:'reference', title:'Rojas Curieux (1998) La lengua páez', url:'https://www.icbf.gov.co/'}, {type:'reference', title:'CRIC — Consejo Regional Indígena del Cauca', url:'https://www.cric-colombia.org/'}] };
LANG_DATA['arn'].meta = { family:'Araucanian (isolate or small family)', speakers:'~400K', countries:'Chile, Argentina', official:'No (recognized minority)', script:'Latin (multiple competing orthographies)', description:{en:'Mapudungun is the language of the Mapuche people of southern Chile and Argentina. Its precise genetic relationships are uncertain — sometimes grouped with Penutian or as an isolate. The "Raguileo" alphabet uses single-letter abbreviations distinctive to Mapuche identity.'} };
LANG_DATA['cr'].meta = { family:'Algic (Algonquian)', speakers:'~95K (all varieties)', countries:'Canada (mainly Saskatchewan, Alberta, Manitoba, Quebec)', official:'Canada (recognized aboriginal language)', script:'Cree syllabics (1840) / Latin', description:{en:'Plains Cree is the largest Cree variety, written in Canadian Aboriginal syllabics invented by missionary James Evans in 1840. The script is a featural abugida where consonant glyphs are rotated to indicate vowels.'} };
LANG_DATA['oj'].meta = { family:'Algic (Algonquian)', speakers:'~50K (all varieties)', countries:'Canada, USA', official:'Canada (recognized aboriginal language)', script:'Latin (Double Vowel) / Cree-style syllabics', description:{en:'Ojibwe (Anishinaabemowin) is one of the largest Algonquian languages, spoken across the Great Lakes region. It is closely related to Ottawa, Algonquin, and Saulteaux. The "Double Vowel" Latin orthography is the most widely used today.'} };
// Mi'kmaq — Eastern Algonquian, Atlantic Canada + Maine, ~7K speakers.
LANG_DATA['mic'].meta = { family:'Algic (Algonquian, Eastern)', speakers:'~7K', countries:'Canada (Nova Scotia, New Brunswick, PEI, Newfoundland, Quebec), USA (Maine, Massachusetts)', official:'Nova Scotia (recognized first language); Canada (recognized aboriginal language)', script:'Latin (Smith-Francis orthography, official since 1980); historically Mi\'kmaw hieroglyphic script', description:{en:'Mi\'kmaq (Mi\'kmawi\'simk, sometimes Micmac) is an Eastern Algonquian language of the Mi\'kmaq people of the Canadian Maritimes (Mi\'kma\'ki) and northern Maine. Polysynthetic with productive verb morphology. Historically used the Mi\'kmaw hieroglyphic script (developed by Catholic missionaries from earlier indigenous mnemonic glyphs and used 1670s–early 20th c.) — one of very few pre-Columbian-era logographic writing traditions in North America. Today written in the Smith-Francis Latin orthography (1980).',ja:'ミクマク語（Mi\'kmawi\'simk、ミクマク族の言葉）はカナダ・マリタイム諸州（ミクマキ）とアメリカ北部メインのミクマク人の東アルゴンキン諸語の言語。多総合的で動詞形態が生産的。歴史的には「ミクマク聖刻文字」（カトリック宣教師が先住民の記憶補助グリフから発展させ、1670年代〜20世紀初頭に使用）を用いており、北米でコロンブス以前期に類似の表語的書記伝統を持つ数少ない例の一つ。現在はスミス＝フランシス式ラテン文字正書法（1980年）で書かれる。',ko:'미크마크어(Mi\'kmawi\'simk, 때로는 Micmac이라고도 함)는 캐나다 마리타임 주(미크마키)와 미국 북부 메인의 미크마크 사람들의 동부 알곤킨어이다. 다종합적이며 동사 형태가 생산적이다. 역사적으로는 미크마크 상형문자(가톨릭 선교사들이 원주민의 기억 보조 글리프로부터 발전시켜 1670년대부터 20세기 초까지 사용)를 사용했으며, 콜럼버스 이전 시대의 표어적 문자 전통을 가진 북미의 몇 안 되는 사례 중 하나이다. 오늘날에는 스미스-프랜시스 라틴 정자법(1980)으로 표기된다.',zh:'米克马克语（Mi\'kmawi\'simk，有时拼作 Micmac）是加拿大马里塔姆诸省（米克马基）和美国北部缅因州的米克马克人的东部阿尔冈昆语。多式综合，动词形态生产丰富。历史上使用米克马克象形文字（由天主教传教士在原住民记忆助记符号基础上发展而成，使用于 1670 年代至 20 世纪初）——这是北美极少数具有前哥伦布时期表意文字传统的语言之一。今日以史密斯-弗朗西斯拉丁正字法（1980）书写。',vi:'Tiếng Mi\'kmaq (Mi\'kmawi\'simk, đôi khi viết là Micmac) là một ngôn ngữ Algonquian Đông của người Mi\'kmaq vùng Maritimes Canada (Mi\'kma\'ki) và bắc Maine. Đa tổng hợp với hình thái động từ phong phú. Trong lịch sử đã dùng chữ tượng hình Mi\'kmaq (do các nhà truyền giáo Công giáo phát triển từ các ký hiệu ghi nhớ bản địa, sử dụng từ những năm 1670 đến đầu thế kỷ 20) — một trong số rất ít truyền thống chữ viết logographic thời tiền-Columbus ở Bắc Mỹ. Ngày nay được viết bằng chính tả Latin Smith-Francis (1980).',de:'Mi\'kmaq (Mi\'kmawi\'simk, manchmal Micmac) ist eine östliche Algonkin-Sprache der Mi\'kmaq in den kanadischen Maritimes (Mi\'kma\'ki) und im nördlichen Maine. Polysynthetisch mit produktiver Verbmorphologie. Historisch wurde die Mi\'kmaq-Hieroglyphenschrift verwendet (von katholischen Missionaren aus älteren indigenen mnemonischen Zeichen entwickelt und etwa 1670 bis Anfang des 20. Jh. genutzt) — eine der ganz wenigen logographischen Schrifttraditionen Nordamerikas mit präkolumbianischen Wurzeln. Heute in der Smith-Francis-Lateinortografie (1980) geschrieben.',fr:'Le mi\'kmaq (Mi\'kmawi\'simk, parfois micmac) est une langue algonquienne orientale du peuple mi\'kmaq des Maritimes canadiennes (Mi\'kma\'ki) et du nord du Maine. Polysynthétique avec une morphologie verbale productive. Historiquement écrit avec les hiéroglyphes mi\'kmaq (développés par les missionnaires catholiques à partir de glyphes mnémoniques indigènes antérieurs, en usage des années 1670 au début du XXe siècle) — l\'une des très rares traditions d\'écriture logographique de l\'Amérique du Nord remontant à l\'époque précolombienne. Aujourd\'hui écrit selon l\'orthographe latine Smith-Francis (1980).'}, sources:[{type:'reference', title:'Glottolog: Mi\'kmaq', url:'https://glottolog.org/resource/languoid/id/mikm1235'}, {type:'reference', title:'Ethnologue: mic', url:'https://www.ethnologue.com/language/mic/'}, {type:'reference', title:'Mi\'gmaq-Mi\'kmaq Online Talking Dictionary', url:'https://www.mikmaqonline.org/'}, {type:'reference', title:'Inglis (1991) Mi\'kmaq Lexicon', url:'https://www.archive.org/'}] };
// Munsee — Algonquian Eastern Lenape, critically endangered, heritage-revival.
LANG_DATA['umu'].meta = { family:'Algic (Algonquian, Eastern, Lenape)', speakers:'~2 (critically endangered, heritage revival ongoing)', countries:'Canada (Ontario — Munsee-Delaware Nation, Moraviantown), USA (NJ/PA/NY historical homeland)', official:'Canada (recognized aboriginal language)', script:'Latin', description:{en:'Munsee (Lunaapeew, "the Lenape language") is an Eastern Algonquian language of the Munsee Lenape people, originally inhabiting the lower Hudson Valley and Delaware River basin (NY/NJ/PA, including the area now called Manhattan). Forced westward by colonial pressure in the 17th-18th centuries, Munsee speakers eventually settled in scattered Ontario reserves (Moraviantown being the linguistic center today). Sister language to Unami Lenape (now extinct). Critically endangered with ~2 fluent elderly speakers; heritage-revival programs at Munsee-Delaware Nation maintain limited transmission.'}, sources:[{type:'reference', title:'Glottolog: Munsee', url:'https://glottolog.org/resource/languoid/id/muns1238'}, {type:'reference', title:'Ethnologue: umu', url:'https://www.ethnologue.com/language/umu/'}, {type:'reference', title:'Goddard (1979) Delaware Verbal Morphology', url:'https://www.jstor.org/'}], scriptTags:['Latin'] };
LANG_DATA['lkt'].meta = { family:'Siouan', speakers:'~2K', countries:'USA (Dakotas, Nebraska, Montana)', official:'No (tribal recognition)', script:'Latin (with diacritics ŋ ȟ č ǧ š ž)', description:{en:'Lakota is the language of the Teton Sioux. Severely endangered with most fluent speakers elderly, it is the focus of major revitalization efforts. The standardized orthography uses ȟ for /ʁ/, č for /tʃ/, and over-bars for aspirated consonants.'} };
LANG_DATA['kl'].meta = { family:'Eskimo-Aleut (Inuit)', speakers:'~57K', countries:'Greenland', official:'Greenland (sole official language)', script:'Latin (with q for /q/)', description:{en:'Greenlandic (Kalaallisut) is the only Eskimo-Aleut language with official status as a sole national language. It is highly polysynthetic — a single word can encode what would be a full sentence in English. The Kalaallisut standard is based on the West Greenlandic dialect.'} };

// === Phase 3D: Caucasus metadata ===
LANG_DATA['ce'].meta = { family:'NE Caucasian (Nakh)', speakers:'~2M', countries:'Russia (Chechnya), diaspora', official:'Chechen Republic', script:'Cyrillic', description:{en:'Chechen is the largest Northeast Caucasian language. It has a notably complex consonant inventory including ejectives, pharyngeals, and a glottal stop, plus an unusual case system with up to 8 cases.'} };
LANG_DATA['inh'].meta = { family:'NE Caucasian (Nakh)', speakers:'~400K', countries:'Russia (Ingushetia)', official:'Republic of Ingushetia', script:'Cyrillic', description:{en:'Ingush is closely related to Chechen — together they form the Nakh branch. The two languages are partially mutually intelligible, sharing about 80% of their core vocabulary.'} };
LANG_DATA['av'].meta = { family:'NE Caucasian (Avar-Andic)', speakers:'~1M', countries:'Russia (Daghestan), Azerbaijan', official:'Republic of Daghestan', script:'Cyrillic', description:{en:'Avar is the largest of the Northeast Caucasian (Daghestanian) languages, used as a lingua franca among speakers of the smaller Andic and Tsezic languages. It has 4 noun classes and a complex case system.'} };
LANG_DATA['lez'].meta = { family:'NE Caucasian (Lezgic)', speakers:'~800K', countries:'Russia (Daghestan), Azerbaijan', official:'Republic of Daghestan', script:'Cyrillic', description:{en:'Lezgian is the largest Lezgic language and one of Daghestan\'s major literary languages. It has rich consonant clusters, voiceless ejectives, and an unusual two-way distinction between regular and pharyngealized vowels in some analyses.'} };
LANG_DATA['dar'].meta = { family:'NE Caucasian (Dargic)', speakers:'~500K', countries:'Russia (Daghestan)', official:'Republic of Daghestan', script:'Cyrillic', description:{en:'Dargwa is the cover term for a group of closely related but often mutually unintelligible varieties spoken in central Daghestan. It is sometimes called a "language complex" rather than a single language.'} };
LANG_DATA['lbe'].meta = { family:'NE Caucasian (Lak-Dargic)', speakers:'~150K', countries:'Russia (Daghestan)', official:'Republic of Daghestan', script:'Cyrillic', description:{en:'Lak is a Northeast Caucasian language native to the central Daghestani highlands. Despite its small speaker base, it has a long literary tradition and a distinctive 4-class noun system.'} };
LANG_DATA['tab'].meta = { family:'NE Caucasian (Lezgic)', speakers:'~125K', countries:'Russia (Daghestan)', official:'Republic of Daghestan', script:'Cyrillic', description:{en:'Tabasaran is famous in linguistic literature for having one of the largest case inventories of any language — historical accounts cite up to 48 cases, though modern analyses typically recognize a smaller number.'} };
// Kumyk — Kipchak Turkic, ~440K, Daghestan Russia. Historical lingua franca of the North Caucasus.
LANG_DATA['kum'].meta = { family:'Turkic (Kipchak, Kipchak-Cuman)', speakers:'~440K', countries:'Russia (Daghestan, Chechnya, North Ossetia, Stavropol Krai)', official:'Republic of Daghestan (one of 14 official languages)', script:'Cyrillic (with гь, гъ, къ, нг, оь, уь, hь, чъ for non-Russian phonemes)', pronunciationType:'broad', description:{en:'Kumyk (Къумукъ тил) is a Kipchak Turkic language spoken predominantly in lowland Daghestan along the Caspian coast and adjacent Chechnya, North Ossetia, and Stavropol Krai. From the medieval period through the 19th century, Kumyk served as the lingua franca of the North Caucasus among diverse mountain peoples, similar to Turki in Central Asia. Closely related to Karachay-Balkar (krc), Crimean Tatar, and Karaim within the Kipchak-Cuman subgroup. One of the 14 official languages of the Republic of Daghestan.',ja:'クムク語（Къумукъ тил）はカスピ海沿岸の低地ダゲスタンおよび隣接するチェチェン、北オセチア、スタヴロポリ地方で主に話されるキプチャク・テュルク諸語の言語。中世から19世紀にかけて、クムク語は北コーカサスの多様な山岳民族間のリングア・フランカとして機能し、中央アジアのトルキー語と類似の役割を果たした。キプチャク・クマン亜群内でカラチャイ・バルカル語（krc）、クリミア・タタール語、カライム語と近縁。ダゲスタン共和国の14公用語の一つ。',ko:'쿠믹어(Къумукъ тил)는 카스피해 연안의 저지대 다게스탄과 인접한 체첸, 북오세티야, 스타브로폴 지방에서 주로 사용되는 키프차크 튀르크어이다. 중세부터 19세기에 걸쳐 쿠믹어는 중앙아시아의 튀르키어와 유사하게 북코카서스의 다양한 산악 민족들 간의 링구아 프랑카로 기능했다. 키프차크-쿠만 하위 어군 내에서 카라차이-발카르어(krc), 크림 타타르어, 카라임어와 가까운 친족 관계이다. 다게스탄 공화국의 14개 공용어 중 하나이다.',zh:'库梅克语（Къумукъ тил）是主要使用于里海沿岸的低地达吉斯坦和邻近的车臣、北奥塞梯、斯塔夫罗波尔边疆区的钦察突厥语。从中世纪到 19 世纪，库梅克语在北高加索多元山地民族之间作为通用语，作用类似中亚的突厥语。在钦察-钦察人亚组中与卡拉恰伊-巴尔卡尔语（krc）、克里米亚鞑靼语、卡拉伊姆语关系密切。是达吉斯坦共和国 14 种官方语言之一。',vi:'Tiếng Kumyk (Къумукъ тил) là một ngôn ngữ Turk Kipchak được nói chủ yếu ở vùng đồng bằng Dagestan dọc bờ biển Caspi và các vùng lân cận như Chechnya, Bắc Ossetia và Stavropol Krai. Từ thời trung cổ đến thế kỷ 19, tiếng Kumyk từng là ngôn ngữ chung của các dân tộc miền núi đa dạng ở Bắc Kavkaz, tương tự vai trò của tiếng Turki ở Trung Á. Gần gũi với tiếng Karachay-Balkar (krc), Tatar Krym và Karaim trong tiểu nhóm Kipchak-Cuman. Là một trong 14 ngôn ngữ chính thức của Cộng hòa Dagestan.',de:'Kumykisch (Къумукъ тил) ist eine kiptschakisch-türkische Sprache, die vorwiegend im Tiefland Dagestans an der Kaspischen Küste sowie in angrenzenden Teilen Tschetscheniens, Nord-Ossetiens und der Region Stawropol gesprochen wird. Vom Mittelalter bis ins 19. Jahrhundert diente Kumykisch als Lingua franca der unterschiedlichen Bergvölker des Nordkaukasus, ähnlich wie das Turki in Zentralasien. Eng verwandt mit Karatschai-Balkarisch (krc), Krimtatarisch und Karaimisch innerhalb der kiptschakisch-kumanischen Untergruppe. Eine der 14 Amtssprachen der Republik Dagestan.',fr:'Le koumyk (Къумукъ тил) est une langue turque kiptchak parlée principalement dans le bas-pays daghestanais le long de la côte caspienne et dans les régions adjacentes de Tchétchénie, Ossétie du Nord et du kraï de Stavropol. Du Moyen Âge au XIXe siècle, le koumyk a servi de lingua franca dans le Caucase du Nord parmi divers peuples montagnards, à l\'image du turki en Asie centrale. Étroitement apparenté au karatchaï-balkar (krc), au tatar de Crimée et au karaïm au sein du sous-groupe kiptchak-couman. L\'une des 14 langues officielles de la République du Daghestan.'}, sources:[{type:'reference', title:'Glottolog: Kumyk', url:'https://glottolog.org/resource/languoid/id/kumy1244'}, {type:'reference', title:'Ethnologue: kum', url:'https://www.ethnologue.com/language/kum/'}, {type:'reference', title:'Bammatov (1969) Kumyk-Russian Dictionary', url:'https://www.archive.org/'}] };
LANG_DATA['ady'].meta = { family:'NW Caucasian (Circassian)', speakers:'~600K', countries:'Russia (Adygea), Turkey, Jordan, Syria, Israel', official:'Republic of Adygea', script:'Cyrillic', description:{en:'Adyghe (West Circassian) has one of the largest consonant inventories of any language (over 50 phonemes), but only 2 or 3 phonemic vowels. The 19th-century Russian conquest scattered most Circassians across the Ottoman Empire.'} };
LANG_DATA['kbd'].meta = { family:'NW Caucasian (Circassian)', speakers:'~1.6M', countries:'Russia (Kabardino-Balkaria, Karachay-Cherkessia), Turkey, Jordan', official:'Russian republics', script:'Cyrillic', description:{en:'Kabardian (East Circassian) shares much of its grammar and vocabulary with Adyghe but has diverged enough to be considered a separate language. It has fewer consonants than Adyghe but more complex prefixal verbal morphology.'} };
LANG_DATA['ab'].meta = { family:'NW Caucasian (Abkhaz-Abaza)', speakers:'~190K', countries:'Abkhazia, Turkey, Russia', official:'Abkhazia', script:'Cyrillic (with extra letters)', description:{en:'Abkhaz has only 2 phonemic vowels (a, ə) but over 50 consonants, and uses an extended Cyrillic alphabet of 64 letters. Almost every noun begins with the article prefix "а-".'} };
LANG_DATA['xmf'].meta = { family:'Kartvelian', speakers:'~500K', countries:'Georgia (Samegrelo)', official:'No (recognized regional)', script:'Georgian (Mkhedruli)', description:{en:'Mingrelian is the second-largest Kartvelian language after Georgian, and the closest relative of Georgian along with Laz. Speakers are typically bilingual in Georgian, which serves as the literary register.'} };
LANG_DATA['os'].meta = { family:'Iranian (Eastern)', speakers:'~600K', countries:'Russia (North Ossetia), South Ossetia, Georgia', official:'North Ossetia, South Ossetia', script:'Cyrillic', description:{en:'Ossetian is the only Iranian language of the Caucasus and the modern descendant of Scytho-Sarmatian. It preserves several archaic Iranian features and has been heavily shaped by contact with Caucasian languages, including borrowing of glottalized consonants.'} };

// === Phase 3E: Pacific & Australia metadata ===
LANG_DATA['ty'].meta = { family:'Austronesian (Polynesian, Eastern)', speakers:'~125K', countries:'French Polynesia', official:'French Polynesia (with French)', script:'Latin (with \' for glottal stop)', description:{en:'Tahitian is the most spoken Polynesian language of French Polynesia and a major lingua franca across the territory. It has only 9 phonemes (5 vowels + 4 consonants in some analyses, plus the glottal stop), giving it a particularly open syllable structure.'} };
LANG_DATA['niu'].meta = { family:'Austronesian (Polynesian, Tongic)', speakers:'~9K', countries:'Niue, New Zealand', official:'Niue', script:'Latin', description:{en:'Niuean is the language of the small Pacific nation of Niue, closely related to Tongan. Most speakers now live in New Zealand, where Niuean is taught in some schools. The language preserves several archaic Polynesian features.'} };
LANG_DATA['tvl'].meta = { family:'Austronesian (Polynesian, Ellicean)', speakers:'~10K', countries:'Tuvalu', official:'Tuvalu', script:'Latin', description:{en:'Tuvaluan is the national language of Tuvalu, one of the world\'s smallest sovereign states. It is closely related to Samoan and Tokelauan, with which it shares a recent common ancestor in the Ellicean Polynesian subgroup.'} };
LANG_DATA['rap'].meta = { family:'Austronesian (Polynesian, Eastern)', speakers:'~3.5K', countries:'Chile (Easter Island)', official:'Easter Island (recognized)', script:'Latin (also Rongorongo, undeciphered)', description:{en:'Rapanui is the indigenous language of Easter Island. It is the most isolated Polynesian language, having been separated from its relatives for over a millennium. The undeciphered Rongorongo script of the island remains one of linguistics\' great mysteries.'} };
LANG_DATA['rar'].meta = { family:'Austronesian (Polynesian, Tahitic)', speakers:'~13K', countries:'Cook Islands, New Zealand', official:'Cook Islands (with English)', script:'Latin', description:{en:'Cook Islands Māori (Reo Māori Kuki Āirani) is the indigenous language of the Cook Islands, closely related to New Zealand Māori and Tahitian. Each inhabited island has its own distinctive variety, with Rarotongan as the de facto standard.'} };
LANG_DATA['mh'].meta = { family:'Austronesian (Micronesian)', speakers:'~55K', countries:'Marshall Islands', official:'Marshall Islands (with English)', script:'Latin (with diacritics ḷ ṃ ņ ñ)', description:{en:'Marshallese is the national language of the Marshall Islands. Its phonology is unusual for Micronesian, with a four-way velarized/palatalized contrast on consonants and a vowel system traditionally analyzed as having only 4 underlying vowels.'} };
LANG_DATA['gil'].meta = { family:'Austronesian (Micronesian)', speakers:'~120K', countries:'Kiribati', official:'Kiribati (with English)', script:'Latin', description:{en:'Gilbertese (Te taetae ni Kiribati) is the national language of Kiribati. It has only 13 phonemes — one of the smallest inventories in the world — and is the only major Micronesian language with significant speakers in Solomon Islands and Fiji as well.'} };
LANG_DATA['ch'].meta = { family:'Austronesian (Western Malayo-Polynesian)', speakers:'~50K', countries:'Guam, Northern Mariana Islands', official:'Guam, CNMI (with English)', script:'Latin', description:{en:'Chamorro is the indigenous language of Guam and the Northern Mariana Islands. Centuries of Spanish rule left an enormous Spanish vocabulary layer, and the noun phrase has been thoroughly restructured around Spanish patterns.'} };
