LANG_DATA['shi'].meta = { family:'Afro-Asiatic (Berber)', speakers:'~7M', countries:'Morocco', official:'Morocco (Tamazight, official 2011)', script:'Tifinagh / Latin / Arabic', description:{en:'Tashelhit (Shilha) is the largest Berber language in Morocco, native to the western High Atlas, Anti-Atlas, and Souss valley. It has a long literary tradition (since at least the 12th century) using Arabic script, alongside the modern Neo-Tifinagh standardization.'} };
LANG_DATA['rif'].meta = { family:'Afro-Asiatic (Berber)', speakers:'~5M', countries:'Morocco, diaspora', official:'Morocco (Tamazight)', script:'Tifinagh / Latin / Arabic', description:{en:'Tarifit (Riffian Berber) is the Berber variety of the Rif mountains in northern Morocco. It is notably divergent from other Moroccan Berber varieties, with strong spirantization of stops (b > β, d > ð, etc.) reminiscent of Welsh.'} };
LANG_DATA['mwr'].meta = { family:'Indo-Aryan (Western)', speakers:'~30M', countries:'India (Rajasthan), Pakistan (Sindh)', official:'No (recognized)', script:'Devanagari', description:{en:'Marwari is the most widely spoken Rajasthani language, native to the Marwar region around Jodhpur. The Marwari merchant community has spread the language across India through diaspora trade networks. It has phonemic retroflex flap ɽ.'} };
LANG_DATA['bgc'].meta = { family:'Indo-Aryan (Western)', speakers:'~13M', countries:'India (Haryana, Delhi)', official:'No (regional)', script:'Devanagari', description:{en:'Haryanvi is the language of the state of Haryana, surrounding Delhi. It is closely related to standard Hindi but preserves several Western Hindi features and has a distinctive intonation pattern often noted in Indian media.'} };
LANG_DATA['ks'].meta = { family:'Indo-Aryan (Dardic)', speakers:'~7M', countries:'India (Jammu & Kashmir), Pakistan (Azad Kashmir)', official:'India (8th Schedule)', script:'Perso-Arabic (modified Nastaliq) / Devanagari / Sharada (historical)', description:{en:'Kashmiri is a Dardic Indo-Aryan language with several archaic features, including a V2 word order unique among Indo-Aryan and an elaborate noun class system. The Sharada script was used historically; today Perso-Arabic Nastaliq is standard.'} };
