// === Phase 3H: Sinitic varieties metadata ===
LANG_DATA['mnp'].meta = { family:'Sinitic (Min Bei)', speakers:'~10M', countries:'China (NW Fujian)', official:'No (regional)', script:'Traditional/Simplified Chinese', description:{en:'Min Bei (Northern Min) is a Min Sinitic variety centered on Jian\'ou in northwestern Fujian. It is one of the original branches in the standard Min classification and preserves several distinct phonological features, including a 6-tone system.'} };
LANG_DATA['nan_te'].meta = { family:'Sinitic (Min Nan, Chao-Shan)', speakers:'~10M+', countries:'China (Chaoshan), Thailand, Singapore, Malaysia, Vietnam', official:'No (recognized regional)', script:'Traditional Chinese / Peng\'im', description:{en:'Teochew (Chaozhou) is a Min Nan variety distinct from Taiwanese Hokkien, with limited mutual intelligibility despite shared roots. The Teochew-speaking diaspora is enormous, particularly in Thailand (~5M), Cambodia, and Singapore.'}, parentCode:'nan' };
LANG_DATA['yue_ts'].meta = { family:'Sinitic (Yue, Sze Yap)', speakers:'~3M+', countries:'China (Taishan), USA, Canada (early diaspora)', official:'No (regional)', script:'Traditional Chinese', description:{en:'Taishanese (Toisanese) is a Yue Chinese variety distinct from standard Cantonese, characterized by lateral fricatives /ɬ/ where Cantonese has /s/. It was the dominant Chinese variety in early Chinese-American communities (19th–early 20th century).'}, parentCode:'yue' };
LANG_DATA['czh'].meta = { family:'Sinitic (Hui)', speakers:'~3-4M', countries:'China (S Anhui, NE Jiangxi, NW Zhejiang)', official:'No (regional)', script:'Simplified Chinese', description:{en:'Hui (Huizhou) Chinese is sometimes classified as a separate top-level Sinitic branch, sometimes grouped with Wu or Gan. It has a complex 6-7 tone system and has preserved archaic features lost in surrounding Mandarin and Wu varieties.'} };
LANG_DATA['cnp'].meta = { family:'Sinitic (Pinghua)', speakers:'~6M', countries:'China (Guangxi)', official:'No (regional)', script:'Simplified Chinese', description:{en:'Pinghua is a controversial Sinitic group spoken in Guangxi, debated as either a top-level Sinitic branch or a sub-branch of Cantonese. It shows extensive contact with Tai-Kadai (Zhuang) languages of the region.'} };
LANG_DATA['zh_jh'].meta = { family:'Sinitic (Mandarin, Jianghuai)', speakers:'~70M', countries:'China (lower Yangtze: Jiangsu, Anhui)', official:'No (regional)', script:'Simplified Chinese', description:{en:'Jianghuai (Lower Yangtze) Mandarin is a major Mandarin sub-branch spoken between the Yangtze and Huai rivers. Nanjing was historically a prestige center; the variety is distinguished from standard Mandarin by preserving the entering tone (rusheng) with glottal stop.'}, parentCode:'zh' };
LANG_DATA['zh_tj'].meta = { family:'Sinitic (Mandarin, Ji-Lu)', speakers:'~10M', countries:'China (Tianjin metro)', official:'No (regional)', script:'Simplified Chinese', description:{en:'Tianjin Mandarin is famous for its low-falling first tone (˩˩, opposite of standard Mandarin\'s high level) and its distinctive use of the particle 嘛 (ma) and the phrase 嘛事 (mashi, "what\'s up"). It is widely heard in Chinese stand-up comedy traditions.'}, parentCode:'zh' };
LANG_DATA['zh_lz'].meta = { family:'Sinitic (Mandarin, Lan-Yin)', speakers:'~5M', countries:'China (Gansu, Ningxia, Inner Mongolia)', official:'No (regional)', script:'Simplified Chinese', description:{en:'Lanyin Mandarin is the Mandarin variety of northwestern China, centered on Lanzhou. It shows a distinctive tone system with only 3 tones in some sub-varieties and notable contact influence from Tibetan and Mongolic languages.'}, parentCode:'zh' };
LANG_DATA['dng'].meta = { family:'Sinitic (Mandarin)', speakers:'~150K', countries:'Kyrgyzstan, Kazakhstan, Russia, Uzbekistan', official:'No (recognized minority)', script:'Cyrillic (Dungan alphabet, since 1953)', description:{en:'Dungan is a variety of Mandarin spoken by the Dungan (Hui-descended) people of Central Asia, descended from 19th-century refugees from northwest China. Uniquely among Sinitic languages, it is written in Cyrillic, with extensive Russian and Persian-Arabic loanwords.'} };

// === Phase 3I: European minority + Uralic minority metadata ===
LANG_DATA['hsb'].meta = { family:'Slavic (West, Sorbian)', speakers:'~13K', countries:'Germany (Lusatia)', official:'Saxony / Brandenburg (regional)', script:'Latin (with č š ž ć ł ó ě ń ŕ)', description:{en:'Upper Sorbian is the more vital of the two Sorbian languages, spoken in Catholic Lusatia near Bautzen. It is the smallest West Slavic language and has been continuously documented since 16th-century Reformation translations.'} };
LANG_DATA['csb'].meta = { family:'Slavic (West, Lechitic)', speakers:'~108K', countries:'Poland (Pomerania)', official:'Poland (regional)', script:'Latin (with ã é ë ł ò ó ô ù ż)', description:{en:'Kashubian is a West Slavic language closely related to Polish, spoken in Pomerania around Gdańsk. It uniquely preserves the West Slavic nasal ã and the labialized ò, ù, and has been recognized as a separate language (rather than a Polish dialect) since 2005.'} };
// Rusyn — East Slavic, multi-country, recognized in Slovakia + Serbia (Vojvodina).
LANG_DATA['rue'].meta = { family:'Indo-European (Slavic, East)', speakers:'~600K', countries:'Slovakia (NE Prešov region), Ukraine (Transcarpathia), Poland (Lemkivshchyna), Serbia (Vojvodina), Hungary, Romania, USA/Canada diaspora', official:'Slovakia (recognized 1995); Serbia (Vojvodina co-official)', script:'Cyrillic (Slovak/Ukrainian standard with і ї ы ё) / Latin (Pannonian Rusyn)', description:{en:'Rusyn (Русиньскый, also called Carpatho-Rusyn or Lemko in Poland) is an East Slavic language traditionally classified as a dialect of Ukrainian by Soviet/Ukrainian linguistics but as a distinct language by most Western Slavists and by the official-language status it holds in Slovakia (since 1995) and Serbia (Vojvodina). Spoken across Slovakia, Ukrainian Transcarpathia, Polish Lemkivshchyna, Hungary, Romania, and Vojvodina (Pannonian Rusyn). The Slovak Rusyn standard (codified 1995 by the Rusyn Renaissance Society) is the most widely used.',ja:'ルシン語（Русиньскый、カルパティア・ルシン語または（ポーランドでは）レムコ語とも）は東スラヴ諸語の言語であり、ソビエト／ウクライナ言語学では伝統的にウクライナ語の方言として分類されてきたが、欧米のスラヴ学者の多くと、スロバキア（1995年以降）およびセルビア（ヴォイヴォディナ）で享受する公用語地位によって独立した言語と見なされる。スロバキア、ウクライナのザカルパチア州、ポーランドのレムコ地方、ハンガリー、ルーマニア、ヴォイヴォディナ（パンノニア・ルシン語）に分布する。スロバキア・ルシン標準（1995年にルシン文化復興協会が成文化）が最も広く使われる。',ko:'루신어(Русиньскый, 카르파티아 루신어 또는 폴란드에서는 렘코어로도 불림)는 동슬라브어이며, 소비에트/우크라이나 언어학에서는 전통적으로 우크라이나어의 방언으로 분류되었으나, 대부분의 서구 슬라브학자들과 슬로바키아(1995년 이후) 및 세르비아(보이보디나)에서 누리는 공용어 지위에 의해 별개의 언어로 간주된다. 슬로바키아, 우크라이나 자카르파티아주, 폴란드 렘코 지역, 헝가리, 루마니아, 보이보디나(판노니아 루신어)에 분포한다. 슬로바키아 루신 표준(1995년 루신 부흥협회가 성문화)이 가장 널리 사용된다.',zh:'卢森尼亚语（Русиньскый，亦称喀尔巴阡-卢森尼亚语，在波兰称作莱姆科语）是东斯拉夫语系的语言，苏联/乌克兰语言学传统上将其归类为乌克兰语方言，但大多数西方斯拉夫学者以及它在斯洛伐克（1995 年起）和塞尔维亚（伏伊伏丁那）享有的官方语言地位将其视为独立语言。分布于斯洛伐克、乌克兰外喀尔巴阡州、波兰莱姆科地区、匈牙利、罗马尼亚和伏伊伏丁那（潘诺尼亚卢森尼亚语）。斯洛伐克卢森尼亚语标准（1995 年卢森尼亚文艺复兴协会规范化）使用最广。',vi:'Tiếng Rusyn (Русиньскый, còn gọi là Carpatho-Rusyn hoặc Lemko ở Ba Lan) là một ngôn ngữ Slav Đông, theo truyền thống ngôn ngữ học Xô viết/Ukraine bị xếp là một phương ngữ tiếng Ukraine, nhưng phần lớn các nhà Slav học phương Tây và quy chế ngôn ngữ chính thức tại Slovakia (từ 1995) và Serbia (Vojvodina) coi đây là ngôn ngữ riêng. Được nói trên khắp Slovakia, vùng Transcarpathia của Ukraine, vùng Lemkivshchyna của Ba Lan, Hungary, Romania và Vojvodina (tiếng Rusyn Pannonia). Chuẩn Rusyn Slovakia (do Hội phục hưng Rusyn quy chuẩn năm 1995) được sử dụng rộng rãi nhất.',de:'Russinisch (Русиньскый, auch Karpatorussinisch oder in Polen Lemkisch) ist eine ostslawische Sprache, die von der sowjetischen/ukrainischen Sprachwissenschaft traditionell als Dialekt des Ukrainischen eingeordnet wurde, von den meisten westlichen Slavisten und durch ihren amtssprachlichen Status in der Slowakei (seit 1995) und Serbien (Vojvodina) jedoch als eigenständige Sprache gilt. Verbreitet in der Slowakei, der ukrainischen Transkarpatien, der polnischen Lemkivshchyna, in Ungarn, Rumänien und in der Vojvodina (Pannonisches Russinisch). Der slowakische Russinisch-Standard (1995 von der Russinischen Renaissance-Gesellschaft kodifiziert) ist am weitesten verbreitet.',fr:'Le rusyn (Русиньскый, aussi appelé carpatho-rusyn ou lemko en Pologne) est une langue slave orientale traditionnellement classée comme dialecte de l\'ukrainien par la linguistique soviétique/ukrainienne, mais considérée comme une langue à part par la plupart des slavistes occidentaux et par le statut officiel qu\'elle détient en Slovaquie (depuis 1995) et en Serbie (Voïvodine). Parlée en Slovaquie, en Transcarpatie ukrainienne, dans la Lemkivchtchyna polonaise, en Hongrie, en Roumanie et en Voïvodine (rusyn pannonien). Le standard slovaque (codifié en 1995 par la Société de la Renaissance Rusyn) est le plus largement utilisé.'}, sources:[{type:'reference', title:'Glottolog: Rusyn', url:'https://glottolog.org/resource/languoid/id/rusy1239'}, {type:'reference', title:'Ethnologue: rue', url:'https://www.ethnologue.com/language/rue/'}, {type:'reference', title:'Plišková (2007) Rusyn Language in Slovakia', url:'https://www.unipo.sk/'}] };
LANG_DATA['fur'].meta = { family:'Romance (Rhaeto-Romance)', speakers:'~600K', countries:'Italy (Friuli)', official:'Italy (recognized minority)', script:'Latin (with â ê î ô û)', description:{en:'Friulian (Furlan) is the largest Rhaeto-Romance language, spoken in northeastern Italy. Closely related to Romansh and Ladin, it preserves Latin features lost in Italian, including final consonants and a more conservative vowel system.'} };
LANG_DATA['ast'].meta = { family:'Romance (Iberian, Astur-Leonese)', speakers:'~110K (~600K passive)', countries:'Spain (Asturias, León), Portugal', official:'Spain (recognized but not official in Asturias)', script:'Latin', description:{en:'Asturian is the principal Astur-Leonese language. It preserves Latin features lost in Spanish, including the diphthongs /ie/ and /uo/, and uses ⟨ll⟩ for /ʎ/ versus Spanish /ʝ/. Officially recognized but stops short of full co-official status.'} };
// Extremaduran (Estremeñu) — Iberian-Romance, ~200K speakers, Extremadura Spain.
LANG_DATA['ext'].meta = { family:'Indo-European (Romance, Italic, Iberian, Astur-Leonese)', speakers:'~200K (UNESCO: definitely endangered)', countries:'Spain (Extremadura — Cáceres, Badajoz)', official:'No (Spanish is sole official); recognized regional cultural language', script:'Latin', description:{en:'Extremaduran (Estremeñu, also "castúo" in some informal uses) is an Astur-Leonese Romance variety transitional between Asturian (ast) and Spanish, spoken in the Extremadura region of western Spain. Most strongly preserved in northern Cáceres province (the "alta extremadura" zone). Heavily influenced by Spanish through centuries of dialect leveling, but retains characteristic Astur-Leonese features: aspirated h- (Latin f-) where Spanish has silent h, mid-vowel diphthongization, and distinctive pronunciation of -s as aspiration. UNESCO classifies it as definitely endangered. Extremaduran Wikipedia (2008) helped revitalize written use.',ja:'エストレマドゥーラ語（Estremeñu、口語で「カストゥオ」とも）はスペイン西部エストレマドゥーラ州で話されるアストゥリアス・レオン系ロマンス語派の言語で、アストゥリアス語（ast）とスペイン語の中間的位置にある。北カセレス県（「アルタ・エストレマドゥーラ」地域）で最も強く保存される。何世紀にもわたる方言平準化によりスペイン語の影響を強く受けたが、アストゥリアス・レオン系の特徴を保持：ラテン語 f- に対する有気 h- (スペイン語は無音 h)、中母音二重母音化、語末 -s の有気音化。UNESCOは「明確に危機」と分類。2008年に立ち上げられたエストレマドゥーラ語版ウィキペディアが書記利用の復興に貢献した。',ko:'에스트레마두라어(Estremeñu, 구어로 "카스투오"라고도 함)는 스페인 서부 에스트레마두라 지역에서 사용되는 아스투리아스-레온계 로망스어로, 아스투리아스어(ast)와 스페인어의 중간적 위치에 있다. 북부 카세레스 주("알타 에스트레마두라" 지역)에서 가장 강하게 보존된다. 수세기에 걸친 방언 평준화로 스페인어의 영향을 강하게 받았지만, 아스투리아스-레온계 특징을 유지: 라틴어 f-에 대한 유기 h-(스페인어는 묵음 h), 중모음 이중모음화, 어말 -s의 유기음화. UNESCO는 "확실히 위기"로 분류. 2008년 출범한 에스트레마두라어판 위키백과가 표기 사용 부흥에 기여했다.',zh:'埃斯特雷马杜拉语（Estremeñu，口语中亦称"卡斯图奥"）是西班牙西部埃斯特雷马杜拉地区使用的阿斯图利亚斯-莱昂罗曼语，处于阿斯图利亚斯语（ast）与西班牙语的过渡位置。在北卡塞雷斯省（"高埃斯特雷马杜拉"地区）保存最完整。经过数世纪的方言平整受到西班牙语强烈影响，但保留阿斯图利亚斯-莱昂系特征：与西班牙语无声 h 不同的拉丁语 f- 对应有气 h-、中元音二重元音化、词末 -s 的气音化。UNESCO 分类为"明显濒危"。2008 年开通的埃斯特雷马杜拉语维基百科推动了书面使用的复兴。',vi:'Tiếng Extremadura (Estremeñu, đôi khi gọi không chính thức là "castúo") là một biến thể Romance Asturleones, nằm chuyển tiếp giữa tiếng Asturias (ast) và tiếng Tây Ban Nha, được nói tại vùng Extremadura phía tây Tây Ban Nha. Bảo tồn rõ nhất ở phía bắc tỉnh Cáceres (vùng "alta extremadura"). Chịu ảnh hưởng mạnh của tiếng Tây Ban Nha qua hàng thế kỷ san phẳng phương ngữ, nhưng vẫn giữ các đặc trưng Asturleones: h- bật hơi (từ f- Latinh) tương ứng với h câm trong tiếng Tây Ban Nha, sự nhị trùng nguyên âm giữa, và phát âm -s cuối thành âm bật hơi. UNESCO xếp loại "đe dọa rõ ràng". Wikipedia tiếng Extremadura (2008) đã góp phần khôi phục việc sử dụng văn bản.',de:'Estremenisch (Estremeñu, in informeller Verwendung auch „castúo") ist eine asturleonesische romanische Varietät, übergangsweise zwischen Asturisch (ast) und Spanisch, gesprochen in der Region Extremadura im Westen Spaniens. Am stärksten erhalten im nördlichen Cáceres („alta extremadura"). Durch jahrhundertelangen Dialektausgleich stark vom Spanischen beeinflusst, doch mit charakteristischen asturleonesischen Merkmalen: aspiriertes h- (aus lateinischem f-) gegenüber stummem h des Spanischen, Diphthongierung der Mittelvokale und aspirierte Aussprache des auslautenden -s. UNESCO stuft es als „eindeutig bedroht" ein. Die 2008 gestartete estremenische Wikipedia hat zur Wiederbelebung des schriftlichen Gebrauchs beigetragen.',fr:'L\'estrémègne (Estremeñu, parfois « castúo » en usage informel) est une variété romane asturléonaise transitoire entre l\'asturien (ast) et l\'espagnol, parlée dans la région d\'Estrémadure, à l\'ouest de l\'Espagne. Mieux conservé dans le nord de Cáceres (zone de la « alta extremadura »). Fortement influencé par l\'espagnol par des siècles de nivellement dialectal, il conserve néanmoins des traits asturléonais caractéristiques: h- aspiré (issu du f- latin) face au h muet de l\'espagnol, diphtongaison des voyelles moyennes et aspiration du -s final. L\'UNESCO le classe comme « clairement en danger ». La Wikipédia en estrémègne (2008) a contribué à la revitalisation de l\'usage écrit.'}, sources:[{type:'reference', title:'Glottolog: Extremaduran', url:'https://glottolog.org/resource/languoid/id/extr1244'}, {type:'reference', title:'Ethnologue: ext', url:'https://www.ethnologue.com/language/ext/'}, {type:'reference', title:'Viudas Camarasa (1988) Diccionario Extremeño', url:'https://www.dialnet.unirioja.es/'}, {type:'reference', title:'OSCEC — Órgano de Seguimiento y Coordinación del Estremeñu', url:'https://www.oscec.es/'}, {type:'reference', title:'UNESCO Atlas: Extremaduran (definitely endangered)', url:'https://en.wal.unesco.org/'}], parentCode:'es_eu' };
