LANG_DATA['mdf'] && (LANG_DATA['mdf'].meta = { family:'Uralic (Mordvinic)', speakers:'~250K', speakerBasis:'L1', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'mdf', countries:'Russia (Mordovia)', official:'Republic of Mordovia (co-official)', script:'Cyrillic', description:{en:'Moksha is the second Mordvinic language alongside Erzya. Both are state languages of the Republic of Mordovia, but they are not mutually intelligible. Moksha has more speakers and is spoken in the western/southern parts of Mordovia.'}, sources:[{type:'reference', title:'Ethnologue 27: Moksha', url:'https://www.ethnologue.com/language/mdf/'}], parentCode:'myv', varietyRole:'sibling-language' });
