LANG_DATA['lis'].meta = { family:'Sino-Tibetan (Loloish)', speakers:'~1M', countries:'China (Yunnan), Myanmar, Thailand, India', official:'No (recognized minority)', script:'Fraser/Lisu script (Latin-based, 1915) / Pollard / Latin', description:{en:'Lisu is a Loloish Tibeto-Burman language with multiple competing scripts. The Fraser script invented by missionaries in 1915 uses rotated and inverted Latin letters and is now encoded in Unicode (U+A4D0–A4FF).'} };
LANG_DATA['nxq'].meta = { family:'Sino-Tibetan (Naic/Loloish)', speakers:'~310K', countries:'China (Yunnan, Sichuan)', official:'No (recognized minority)', script:'Latin / Dongba pictographs (ritual)', description:{en:'Naxi is famous for its Dongba pictographic script, the only living pictographic writing system in the world, used ritually by Naxi shamans. The everyday Latin orthography uses tone-bearing letters (l h q) appended to syllables.'} };
LANG_DATA['shn'].meta = { family:'Kra-Dai (Tai, Southwestern)', speakers:'~3.3M', countries:'Myanmar (Shan State), Thailand, China', official:'Shan State (Myanmar)', script:'Shan script (Tai Le family, related to Burmese)', description:{en:'Shan is the largest Tai language of Myanmar, closely related to Northern Thai (Lanna). The Shan script is part of the Tai Le family, with curved letters distinct from but historically related to Burmese script.'} };

// === Phase 3K: African Bantu/Khoisan/W. African (more) metadata ===
LANG_DATA['ee'].meta = { family:'Niger-Congo (Kwa, Gbe)', speakers:'~7M', countries:'Ghana, Togo', official:'Togo (recognized national)', script:'Latin (with ƒ ɔ ɖ ɛ ɣ ŋ ʋ)', description:{en:'Ewe (Eʋegbe) is a tonal Gbe language native to southeastern Ghana and southern Togo. It is closely related to Fon and Aja, and uses an extended Latin alphabet with several letters from the Africa Alphabet (1928) including ƒ, ɖ, ɣ, and ʋ.'} };
// Kabiye — Gur language, ~1.2M, Togo (one of two national languages alongside Ewe).
LANG_DATA['kbp'].meta = { family:'Atlantic-Congo (Gur, Eastern Oti-Volta)', speakers:'~1.2M', countries:'Togo (Kara region), Ghana, Benin', official:'Togo (one of two national languages, with Ewe)', script:'Latin (with ɖ ɛ ɣ ŋ ɔ ʋ ʔ + ɩ ʋ)', description:{en:'Kabiye (Kabɩyɛ) is a Gur (Eastern Oti-Volta) language spoken in the Kara region of northern Togo, where the Kabye people are the second-largest ethnic group. Recognized as one of Togo\'s two national languages alongside Ewe, it has standardized orthography developed by SIL and the Togolese government in the 1970s. Tonal with rich vowel inventory including ɩ and ʋ (relative to /i/ and /u/).',ja:'カビエ語（Kabɩyɛ）はトーゴ北部カラ地方で話されるグル語派（東部オティ＝ヴォルタ）の言語で、カビエ人はカラ地方で2番目に大きい民族集団を形成する。エヴェ語と並ぶトーゴの2つの国民言語の一つとして認められ、SILとトーゴ政府が1970年代に開発した標準正書法を持つ。声調を持ち、ɩ・ʋ（／i／・／u／に対応）を含む豊かな母音体系を有する。',ko:'카비예어(Kabɩyɛ)는 토고 북부 카라 지방에서 사용되는 구르어파(동부 오티-볼타) 언어로, 카비예인은 카라 지방에서 두 번째로 큰 민족 집단이다. 에웨어와 함께 토고의 두 국민 언어 중 하나로 인정되며, SIL과 토고 정부가 1970년대에 개발한 표준 정자법을 가진다. 성조를 가지며 ɩ·ʋ(/i/·/u/에 대응)를 포함한 풍부한 모음 체계를 가진다.',zh:'卡比耶语（Kabɩyɛ）是多哥北部卡拉地区使用的古尔语支（东奥蒂-沃尔塔）语言，卡比耶人是卡拉地区第二大族群。与埃维语并列为多哥两种国家语言之一，拥有 SIL 与多哥政府于 1970 年代制定的标准正字法。具有声调，元音系统丰富，包括与 /i/、/u/ 对应的 ɩ、ʋ。',vi:'Tiếng Kabiye (Kabɩyɛ) là một ngôn ngữ Gur (Oti-Volta phương Đông) được nói ở vùng Kara phía bắc Togo, nơi người Kabye là nhóm dân tộc lớn thứ hai. Là một trong hai ngôn ngữ quốc gia của Togo cùng với tiếng Ewe, có chính tả chuẩn do SIL và chính phủ Togo soạn vào những năm 1970. Có thanh điệu và hệ nguyên âm phong phú, gồm các nguyên âm ɩ, ʋ tương ứng với /i/, /u/.',de:'Kabiye (Kabɩyɛ) ist eine Gur-Sprache (östliches Oti-Volta), die in der Region Kara im Norden Togos gesprochen wird, wo die Kabye die zweitgrößte Ethnie sind. Neben Ewe eine der beiden Nationalsprachen Togos, mit einer in den 1970er Jahren von SIL und der Regierung Togos festgelegten Standardorthografie. Tonal mit reichem Vokalsystem, einschließlich der zu /i/ und /u/ korrespondierenden ɩ und ʋ.',fr:'Le kabiyè (Kabɩyɛ) est une langue gour (oti-volta oriental) parlée dans la région de Kara, au nord du Togo, où les Kabyè constituent le deuxième groupe ethnique. Avec l\'éwé, l\'une des deux langues nationales du Togo, dotée d\'une orthographe standard mise au point par la SIL et le gouvernement togolais dans les années 1970. Tonal avec un système vocalique riche, incluant ɩ et ʋ correspondant à /i/ et /u/.'}, sources:[{type:'reference', title:'Glottolog: Kabiye', url:'https://glottolog.org/resource/languoid/id/kabi1261'}, {type:'reference', title:'Ethnologue: kbp', url:'https://www.ethnologue.com/language/kbp/'}, {type:'reference', title:'Roberts (2013) Parlons kabiyè', url:'https://editions-harmattan.fr/'}] };
LANG_DATA['nyn'].meta = { family:'Atlantic-Congo (Bantu)', speakers:'~3M', countries:'Uganda', official:'Uganda (recognized)', script:'Latin', description:{en:'Runyankole-Rukiga is a Bantu language of southwestern Uganda. The combined Runyankole-Rukiga literary form is taught in schools, but Runyankole and Rukiga are sometimes treated as separate languages.'} };
LANG_DATA['luy'].meta = { family:'Atlantic-Congo (Bantu)', speakers:'~6M', countries:'Kenya (western), Uganda', official:'No (recognized)', script:'Latin', description:{en:'Luhya (Luyia) is a cluster of Bantu varieties of western Kenya, sometimes treated as a single language and sometimes as 16 or more. The varieties show considerable internal diversity, with the standardized literary form based on a mixture.'} };
LANG_DATA['ssw'].meta = { family:'Atlantic-Congo (Bantu, Nguni)', speakers:'~2.4M', countries:'Eswatini, South Africa, Mozambique', official:'Eswatini, South Africa', script:'Latin', description:{en:'Swazi (siSwati) is the national language of Eswatini and one of South Africa\'s 11 official languages. It is a Nguni Bantu language closely related to Zulu, Xhosa, and Ndebele, with a four-way distinction in clicks borrowed from Khoisan.'} };
LANG_DATA['nbl'].meta = { family:'Atlantic-Congo (Bantu, Nguni)', speakers:'~1.1M', countries:'South Africa', official:'South Africa', script:'Latin', description:{en:'Southern Ndebele (isiNdebele) is one of South Africa\'s 11 official languages, distinct from Northern Ndebele of Zimbabwe. It is closely related to Zulu but has acquired distinctive vocabulary from extensive contact with neighboring Pedi and Tswana.'}, disambiguator:{en:'(Southern, South Africa)', ja:'（南ンデベレ、南アフリカ）', ko:'(남부, 남아프리카)', zh:'（南恩德贝勒，南非）'} };
// Northern Ndebele — Bantu Nguni, Zimbabwe national language. Distinct from Southern Ndebele (nbl).
LANG_DATA['nd'].meta = { family:'Atlantic-Congo (Bantu, Nguni)', speakers:'~1.6M', countries:'Zimbabwe (Matabeleland, Bulawayo)', official:'Zimbabwe (one of 16 official languages, 2013 constitution)', script:'Latin', description:{en:'Northern Ndebele (isiNdebele) is the main Nguni Bantu language of Zimbabwe, spoken predominantly in Matabeleland with Bulawayo as its cultural centre. It descends from a 19th-century migration of Mzilikazi\'s Nguni people from northern South Africa, making it closely related to Zulu (zu). Distinct from Southern Ndebele (nbl) of South Africa, which split off earlier and developed under different contact conditions. Recognised as one of Zimbabwe\'s 16 official languages under the 2013 constitution.',ja:'北ンデベレ語（isiNdebele）はジンバブエの主要なンゴニ・バントゥー諸語の言語であり、主にマタベレランド地方で話され、ブラワヨを文化中心とする。19世紀のムジリカジ率いるンゴニ族の南アフリカ北部からの移動を起源とし、ズールー語（zu）と近縁。早期に分岐して別の接触条件下で発展した南アフリカの南ンデベレ語（nbl）とは区別される。2013年憲法でジンバブエの16の公用語の一つとして認められている。',ko:'북부 응데벨레어(isiNdebele)는 짐바브웨의 주요 응구니 반투어로, 주로 마타벨레란드 지역에서 사용되며 불라와요를 문화 중심지로 한다. 19세기 음질리카지가 이끈 응구니족의 남아프리카 북부로부터의 이주에 기원을 두며, 줄루어(zu)와 가까운 친족 관계이다. 더 일찍 분기하여 다른 접촉 조건 아래 발전한 남아프리카의 남부 응데벨레어(nbl)와 구분된다. 2013년 헌법에서 짐바브웨의 16개 공용어 중 하나로 인정된다.',zh:'北恩德贝勒语（isiNdebele）是津巴布韦主要的恩古尼班图语，主要使用于马塔贝莱兰地区，以布拉瓦约为文化中心。源自 19 世纪姆兹利卡齐率领的恩古尼人从南非北部的迁徙，与祖鲁语（zu）关系密切。与较早分支并在不同接触条件下发展的南非南恩德贝勒语（nbl）有别。在 2013 年宪法下被列为津巴布韦的 16 种官方语言之一。',vi:'Tiếng Ndebele Bắc (isiNdebele) là ngôn ngữ Bantu Nguni chính của Zimbabwe, được nói chủ yếu ở Matabeleland với Bulawayo là trung tâm văn hóa. Có nguồn gốc từ cuộc di cư thế kỷ 19 của người Nguni dưới sự dẫn dắt của Mzilikazi từ bắc Nam Phi, do đó gần gũi với tiếng Zulu (zu). Khác với tiếng Ndebele Nam (nbl) ở Nam Phi, vốn tách ra sớm hơn và phát triển trong điều kiện tiếp xúc khác. Được công nhận là một trong 16 ngôn ngữ chính thức của Zimbabwe theo hiến pháp 2013.',de:'Nord-Ndebele (isiNdebele) ist die wichtigste Nguni-Bantu-Sprache Simbabwes, hauptsächlich in Matabeleland mit Bulawayo als kulturellem Zentrum gesprochen. Sie geht auf eine Migration der Nguni unter Mzilikazi aus dem nördlichen Südafrika im 19. Jahrhundert zurück und ist daher eng mit Zulu (zu) verwandt. Sie unterscheidet sich vom Süd-Ndebele (nbl) Südafrikas, das sich früher abspaltete und unter anderen Kontaktbedingungen entwickelte. Nach der Verfassung von 2013 als eine von 16 Amtssprachen Simbabwes anerkannt.',fr:'Le ndébélé du Nord (isiNdebele) est la principale langue bantoue nguni du Zimbabwe, parlée principalement au Matabeleland avec Bulawayo comme centre culturel. Il descend d\'une migration au XIXe siècle du peuple nguni de Mzilikazi venu du nord de l\'Afrique du Sud, ce qui le rend proche du zoulou (zu). Distinct du ndébélé du Sud (nbl) d\'Afrique du Sud, qui s\'est séparé plus tôt et s\'est développé dans des conditions de contact différentes. Reconnu comme l\'une des 16 langues officielles du Zimbabwe par la constitution de 2013.'}, disambiguator:{en:'(Northern, Zimbabwe)', ja:'（北ンデベレ、ジンバブエ）', ko:'(북부, 짐바브웨)', zh:'（北恩德贝勒，津巴布韦）'}, sources:[{type:'reference', title:'Glottolog: Northern Ndebele', url:'https://glottolog.org/resource/languoid/id/nort2795'}, {type:'reference', title:'Ethnologue: nde', url:'https://www.ethnologue.com/language/nde/'}, {type:'reference', title:'Pelling (1971) A Practical Ndebele Dictionary', url:'https://www.longman.co.zw/'}, {type:'reference', title:'Constitution of Zimbabwe Amendment (No. 20) Act 2013', url:'https://www.constituteproject.org/'}] };
LANG_DATA['nso'].meta = { family:'Atlantic-Congo (Bantu, Sotho-Tswana)', speakers:'~5M', countries:'South Africa', official:'South Africa', script:'Latin', description:{en:'Northern Sotho (Sesotho sa Leboa, also called Pedi or Sepedi) is one of South Africa\'s 11 official languages, spoken in Limpopo, Gauteng, and Mpumalanga. It groups together about 30 closely related dialects under a unified literary standard.'} };
LANG_DATA['fan'].meta = { family:'Atlantic-Congo (Bantu, A.70 Yaounde-Fang)', speakers:'~1M', countries:'Equatorial Guinea, Gabon, Cameroon, Republic of the Congo', official:'Equatorial Guinea (recognized)', script:'Latin', description:{en:'Fang is a Northwest Bantu language spoken across the Atlantic coast of Equatorial Guinea, Gabon, and southern Cameroon. As a Zone A Bantu language, it preserves several archaic features lost in eastern and southern Bantu varieties.'} };
LANG_DATA['naq'].meta = { family:'Khoe-Kwadi (Khoisan)', speakers:'~250K', countries:'Namibia, South Africa, Botswana', official:'Namibia (recognized national)', script:'Latin (with click letters ǀ ǁ ǂ ǃ)', description:{en:'Nama (Khoekhoegowab) is the largest Khoisan language and the most-spoken click language. It has 4 phonemic click types: ǀ (dental), ǁ (lateral), ǂ (alveolar palatal), ǃ (postalveolar). The clicks are written with their IPA letters in standard orthography.'} };
LANG_DATA['hts'].meta = { family:'Language isolate (or proposed Sandawe-Hadza)', speakers:'~1K', countries:'Tanzania (Lake Eyasi)', official:'No', script:'Latin (with ʼ for clicks/glottal)', description:{en:'Hadza is a critically important language isolate spoken by traditional hunter-gatherers around Lake Eyasi in Tanzania. It has clicks but no proven genetic relation to other click languages, and may represent an independent language family of immense antiquity.'} };
LANG_DATA['kr'].meta = { family:'Nilo-Saharan (Saharan)', speakers:'~9.6M', countries:'Nigeria, Niger, Cameroon, Chad, Sudan, Libya', official:'No (recognized in Nigeria)', script:'Latin / Arabic (Ajami)', description:{en:'Kanuri is the language of the Kanuri people of the Lake Chad basin, descended from the medieval Kanem-Bornu empire. It is one of the largest Nilo-Saharan languages and uses a 6-tone system with implosive consonants ɓ, ɗ, ʄ.'} };
LANG_DATA['men'].meta = { family:'Niger-Congo (Mande, Southwestern)', speakers:'~2M', countries:'Sierra Leone, Liberia', official:'Sierra Leone (recognized)', script:'Latin / Kikakui (Mende script, 1921)', description:{en:'Mende is a major language of Sierra Leone. The Kikakui script invented by Mohammed Turay around 1921 is one of the few indigenous African scripts created in the 20th century, though Latin is now more commonly used.'} };
// Vai — Mande, ~120K speakers, Liberia + Sierra Leone. Has its own indigenous syllabary script.
LANG_DATA['vai'].meta = { family:'Niger-Congo (Mande, Western, Vai-Kono)', speakers:'~120K', countries:'Liberia (Cape Mount, Bomi, Grand Cape Mount counties), Sierra Leone (Pujehun district)', official:'No (English in Liberia, English in Sierra Leone are official); recognized indigenous', script:'Vai (indigenous syllabary, ~1832, Unicode 5.1 (2008) — U+A500–A63F) / Latin', description:{en:'Vai (Vai: ꕙꔤ) is a Western Mande language of Liberia and Sierra Leone, famous for being the only one of the 20+ indigenous African writing systems to have been invented in pre-colonial Africa and to remain in continuous use to the present day. The Vai syllabary was developed around 1832 by Mɔmɔlu Duwalu Bukɛlɛ in a dream-vision and refined by his colleagues — making it both the oldest indigenous African script and one of the few worldwide that emerged in pre-literate societies through individual invention rather than borrowing. The script remained in active community use through the colonial period and was encoded in Unicode 5.1 (2008). The Vai people are linguistically Mande but culturally Mande-Mande/Atlantic boundary, with extensive trade contact patterns.',ja:'ヴァイ語（Vai 文字: ꕙꔤ）はリベリアとシエラレオネの西部マンデ諸語の言語であり、20以上のアフリカ土着文字体系のうち、植民地以前にアフリカで発明され今日まで継続的に使われている唯一の文字を持つ言語として有名。ヴァイ音節文字は1832年頃、モモル・ドゥワル・ブケレが夢のビジョンで開発し同僚らが洗練したもの——アフリカ最古の土着文字であると同時に、借用ではなく個人の発明によって前識字社会から生まれた数少ない文字の一つでもある。文字は植民地時代を通じて共同体内で活発に使われ続け、Unicode 5.1（2008年）で符号化された。ヴァイ人は言語的にはマンデ系だが、文化的にはマンデ・大西洋境界に位置し、広範な交易接触パターンを持つ。',ko:'바이어(바이 문자: ꕙꔤ)는 라이베리아와 시에라리온의 서부 만데어로, 20여 개의 아프리카 토착 문자 체계 중 식민지 이전 아프리카에서 발명되어 오늘날까지 계속 사용되는 유일한 문자를 가진 언어로 유명하다. 바이 음절 문자는 1832년경 모모루 두왈루 부켈레가 꿈의 환상에서 개발하고 동료들이 다듬은 것——아프리카 최초의 토착 문자이자, 차용이 아닌 개인의 발명을 통해 무문자 사회에서 출현한 세계에서 드문 문자 중 하나이다. 식민지 시대를 거쳐 공동체 내에서 활발히 사용되었으며, Unicode 5.1(2008)에서 인코딩되었다. 바이인은 언어적으로 만데계이지만 문화적으로 만데-대서양 경계에 위치하며 광범위한 무역 접촉 패턴을 가진다.',zh:'瓦伊语（瓦伊文字: ꕙꔤ）是利比里亚和塞拉利昂的西部曼德语，以拥有 20 多种非洲土著书写系统中唯一在前殖民时代发明并持续使用至今的文字而闻名。瓦伊音节文字约 1832 年由穆穆鲁·杜瓦鲁·布凯莱在梦中受启示开发，由其同事完善——既是非洲最古老的土著文字，也是世界上少数通过个人发明（而非借用）从前识字社会中产生的文字之一。文字在殖民时代持续在社区内活跃使用，于 Unicode 5.1（2008 年）编码。瓦伊人语言上属曼德系，但文化上位于曼德-大西洋交界，拥有广泛的贸易接触模式。',vi:'Tiếng Vai (chữ Vai: ꕙꔤ) là một ngôn ngữ Mande Tây ở Liberia và Sierra Leone, nổi tiếng nhờ một trong số rất hiếm chữ viết bản địa châu Phi được sáng tạo từ thời tiền thuộc địa và còn dùng liên tục cho đến nay. Bộ âm tiết Vai được Mɔmɔlu Duwalu Bukɛlɛ phát triển khoảng năm 1832 sau một giấc mơ và được các đồng sự hoàn thiện — vừa là một trong những chữ viết bản địa cổ nhất châu Phi, vừa là một trong số ít chữ viết trên thế giới được sáng tạo bởi cá nhân (chứ không phải vay mượn) từ một xã hội tiền văn tự. Chữ Vai vẫn được sử dụng tích cực trong cộng đồng suốt thời thuộc địa và được mã hóa trong Unicode 5.1 (2008). Người Vai thuộc nhánh Mande về ngôn ngữ nhưng nằm ở vùng giao thoa Mande-Đại Tây Dương về văn hóa, với mạng lưới giao thương rộng rãi.',de:'Vai (Vai-Schrift: ꕙꔤ) ist eine westliche Mande-Sprache in Liberia und Sierra Leone, bekannt für eines der ganz wenigen vor der Kolonialzeit erfundenen und seither durchgehend gebräuchlichen indigenen Schriftsysteme Afrikas. Die Vai-Silbenschrift wurde um 1832 von Mɔmɔlu Duwalu Bukɛlɛ nach einem Traum entwickelt und von seinen Mitarbeitern weiter ausgearbeitet — sie ist eine der ältesten indigenen Schriften Afrikas und weltweit eines der wenigen Schriftsysteme, das durch individuelle Erfindung (statt durch Übernahme) aus einer vorliterarischen Gesellschaft hervorging. Die Schrift blieb in den Gemeinden während der Kolonialzeit aktiv in Gebrauch und wurde in Unicode 5.1 (2008) kodiert. Die Vai sind sprachlich Mande, kulturell jedoch an der Mande-Atlantik-Grenze mit weitreichenden Handelskontakten verankert.',fr:'Le vai (écriture vai : ꕙꔤ) est une langue mandée occidentale du Liberia et de la Sierra Leone, célèbre pour l\'un des très rares systèmes d\'écriture indigènes africains inventés avant la colonisation et encore en usage continu. Le syllabaire vai fut développé vers 1832 par Mɔmɔlu Duwalu Bukɛlɛ à la suite d\'un rêve et perfectionné par ses collaborateurs — l\'une des plus anciennes écritures indigènes d\'Afrique et l\'un des rares systèmes au monde issus d\'une invention individuelle (et non d\'un emprunt) dans une société préalphabétique. L\'écriture est restée activement utilisée dans la communauté pendant l\'époque coloniale et a été codée dans Unicode 5.1 (2008). Les Vai sont mandés sur le plan linguistique mais culturellement à la frontière mandé-atlantique, avec d\'importants réseaux commerciaux.'}, sources:[{type:'reference', title:'Glottolog: Vai', url:'https://glottolog.org/resource/languoid/id/vaii1239'}, {type:'reference', title:'Ethnologue: vai', url:'https://www.ethnologue.com/language/vai/'}, {type:'reference', title:'Welmers (1976) A Reference Grammar of Vai', url:'https://www.archive.org/'}, {type:'reference', title:'Tuchscherer (2005) Recording, Communicating and Making Visible: A History of Writing and Systems of Notation in Africa (Sub-Saharan Africa)', url:'https://www.cambridge.org/'}, {type:'reference', title:'Unicode Vai block (U+A500–A63F)', url:'https://www.unicode.org/charts/PDF/UA500.pdf'}] };
LANG_DATA['dyu'].meta = { family:'Niger-Congo (Mande, Manding)', speakers:'~10M (lingua franca, 2-5M L1)', countries:'Burkina Faso, Côte d\'Ivoire, Mali, Ghana', official:'No (recognized regional)', script:'Latin / N\'Ko / Arabic (Ajami)', description:{en:'Dyula (Jula) is a major West African trade lingua franca, mutually intelligible with Bambara and Mandinka (the three together forming the Manding dialect continuum). The N\'Ko script is increasingly used by literate communities.'} };
// Susu (Soso) — Mande, ~1.2M speakers, coastal Guinea + Sierra Leone. National language of Guinea.
LANG_DATA['sus'].meta = { family:'Niger-Congo (Mande, Western, Susu-Yalunka)', speakers:'~1.2M', countries:'Guinea (coastal), Sierra Leone (north), Guinea-Bissau, Senegal', official:'Guinea (one of the eight national languages)', script:'Latin / N\'Ko / Arabic (Ajami)', description:{en:'Susu (Sosokuye, also Soussou) is the principal coastal language of Guinea around the capital Conakry, and one of Guinea\'s eight recognized national languages. A Western Mande language, Susu is closely related to Yalunka but lexically distinct from the Manding cluster (Bambara, Dyula, Mandinka). It is the dominant trade language along Guinea\'s coast and into northern Sierra Leone, where it serves as a market lingua franca alongside Krio.',ja:'スース語（Sosokuye、ソススー語とも）はギニアの首都コナクリ周辺の主要な沿岸言語であり、ギニアの8つの公認国民言語の一つ。西部マンデ諸語の言語で、ヤルンカ語と近縁だが、語彙上はマンディング群（バンバラ、ジュラ、マンディンカ）とは異なる。ギニア沿岸とシエラレオネ北部の主要な交易言語で、シエラレオネ北部ではクリオ語と並ぶ市場リングア・フランカとして機能する。',ko:'수수어(Sosokuye, 소수수어로도 불림)는 기니의 수도 코나크리 일대의 주요 해안 언어이며, 기니의 8개 공인 국민 언어 중 하나이다. 서부 만데어로, 얄룬카어와 가까운 친족 관계이지만 어휘적으로는 만딩 군(밤바라, 줄라, 만딩카)과 구별된다. 기니 해안과 시에라리온 북부의 주요 무역 언어이며, 시에라리온 북부에서는 크리오어와 함께 시장 링구아 프랑카로 기능한다.',zh:'苏苏语（Sosokuye，又称索苏语）是几内亚首都科纳克里周边的主要沿海语言，是几内亚 8 种公认的国家语言之一。属西部曼德语，与亚伦卡语关系密切，但词汇上与曼丁语群（班巴拉、迪乌拉、曼丁卡）不同。是几内亚沿海和塞拉利昂北部的主要贸易语言，在塞拉利昂北部与克里奥尔语并列作为市场通用语。',vi:'Tiếng Susu (Sosokuye, còn gọi là Soussou) là ngôn ngữ ven biển chính của Guinea quanh thủ đô Conakry và là một trong tám ngôn ngữ quốc gia được công nhận của Guinea. Là một ngôn ngữ Mande Tây, gần gũi với tiếng Yalunka nhưng khác biệt về từ vựng với cụm Manding (Bambara, Dyula, Mandinka). Là ngôn ngữ thương mại chính ven biển Guinea và miền bắc Sierra Leone, nơi nó đóng vai trò ngôn ngữ chợ song hành với tiếng Krio.',de:'Susu (Sosokuye, auch Soussou) ist die wichtigste Küstensprache Guineas rund um die Hauptstadt Conakry und eine der acht anerkannten Nationalsprachen des Landes. Es ist eine westliche Mande-Sprache, eng verwandt mit Jalonke, lexikalisch jedoch deutlich verschieden vom Manding-Cluster (Bambara, Dioula, Mandinka). Wichtige Handelssprache an der Küste Guineas und im Norden Sierra Leones, wo sie neben Krio als Marktsprache fungiert.',fr:'Le soussou (Sosokuye, aussi Soussou) est la principale langue côtière de Guinée autour de la capitale Conakry et l\'une des huit langues nationales reconnues du pays. C\'est une langue mandée occidentale, étroitement apparentée au yalunka mais lexicalement distincte du groupe manding (bambara, dioula, mandinka). Importante langue commerciale sur la côte guinéenne et dans le nord de la Sierra Leone, où elle sert de langue de marché aux côtés du krio.'}, sources:[{type:'reference', title:'Glottolog: Susu', url:'https://glottolog.org/resource/languoid/id/susu1250'}, {type:'reference', title:'Ethnologue: sus', url:'https://www.ethnologue.com/language/sus/'}, {type:'reference', title:'Houis (1963) Étude descriptive de la langue susu', url:'https://www.archive.org/'}] };

// === Phase 3L: Indigenous Americas + S Asian + SE Asian metadata ===
LANG_DATA['syl'].meta = { family:'Indo-Aryan (Eastern)', speakers:'~10M+', countries:'Bangladesh (Sylhet), India (Barak Valley), UK diaspora', official:'No (recognized regional)', script:'Bengali / Sylheti Nagari (historical)', description:{en:'Sylheti is sometimes considered a Bengali dialect, but linguistically diverged enough to be classified as a separate language by SIL. The historical Sylheti Nagari script (in Unicode since 2005) is being revived; Bengali script is in everyday use.'} };
// Audit Task 142 (Tier 2): Rohingya — Indo-Aryan, sociolinguistically/politically prominent.
LANG_DATA['rhg'].meta = { family:'Indo-Aryan (Eastern)', speakers:'~1.8M', countries:'Myanmar (Rakhine), Bangladesh (Cox\'s Bazar)', official:'No', script:'Hanifi Rohingya / Latin (online) / Bengali / Arabic-derived (historical)', description:{en:'Rohingya is the language of the Rohingya people of northern Rakhine State (Myanmar), most of whom now live as refugees in Cox\'s Bazar, Bangladesh after the 2017 military operations. Linguistically closest to Chittagonian. The Hanifi Rohingya script (Unicode 11.0, 2018) is the primary modern standard, distinct from the Bengali, Latin, and Arabic-derived alternatives used earlier.',ja:'ロヒンギャ語はミャンマー北部ラカイン州のロヒンギャの人々の言語であり、彼らの多くは2017年の軍事作戦後、バングラデシュのコックスバザールで難民として暮らす。系統的にはチッタゴン語に最も近い。ハニフィ・ロヒンギャ文字（Unicode 11.0、2018年）が主要な現代標準で、それ以前に使われていたベンガル文字・ラテン文字・アラビア文字派生の代替表記と区別される。',ko:'로힝야어는 미얀마 북부 라카인주 로힝야인의 언어이며, 그들 대부분은 2017년 군사 작전 이후 방글라데시 콕스바자르에서 난민으로 살고 있다. 계통적으로 치타공어에 가장 가깝다. 하니피 로힝야 문자(Unicode 11.0, 2018)가 주된 현대 표준으로, 이전에 사용된 벵갈 문자·라틴 문자·아랍 문자 파생 대체 표기와 구분된다.',zh:'罗兴亚语是缅甸北部若开邦罗兴亚人的语言，其中多数自2017年军事行动后作为难民居住在孟加拉国科克斯巴扎尔。语言学上与吉大港语最为接近。哈尼菲罗兴亚文字（Unicode 11.0，2018年）是主要的现代标准，与此前使用的孟加拉文字、拉丁文字以及阿拉伯文字衍生的替代方案有所不同。'}, sources:[{type:'reference', title:'Glottolog: Rohingya', url:'https://glottolog.org/resource/languoid/id/rohi1238'}, {type:'reference', title:'Ethnologue: rhg', url:'https://www.ethnologue.com/language/rhg/'}, {type:'reference', title:'UNESCO Atlas of the World\'s Languages in Danger: Rohingya', url:'https://en.wal.unesco.org/'}] };
// Audit Task 142 (Tier 2): Chittagonian — Eastern Indo-Aryan, often debated as Bengali macrolanguage member.
LANG_DATA['ctg'].meta = { family:'Indo-Aryan (Eastern)', speakers:'~13M', countries:'Bangladesh (Chittagong)', official:'No', script:'Bengali (everyday); Arabic-derived (historical)', description:{en:'Chittagonian is spoken in the Chittagong Division of southeastern Bangladesh. It shares lexicon with Bengali (bn) but differs in phonology and tone enough that the two are not mutually intelligible — Glottolog and Ethnologue treat it as a distinct language, though Bangladeshi state policy treats it as a regional Bengali variety. Closely related to Rohingya across the border.',ja:'チッタゴン語はバングラデシュ南東部のチッタゴン管区で話される。語彙はベンガル語（bn）と共通点があるが、音韻と声調の差が大きく相互理解はできない。Glottolog および Ethnologue は別言語として扱うが、バングラデシュ国家政策上はベンガル語の地域変種として扱われる。国境を越えたロヒンギャ語と近縁関係にある。',ko:'치타공어는 방글라데시 남동부 치타공 관구에서 사용된다. 어휘는 벵골어(bn)와 공유하지만 음운과 성조 차이가 커서 상호 이해가 불가능하다. Glottolog와 Ethnologue는 별개 언어로 취급하나 방글라데시 국가 정책은 벵골어의 지역 변종으로 분류한다. 국경 너머 로힝야어와 가까운 친족 관계이다.',zh:'吉大港语使用于孟加拉国东南部吉大港专区。词汇与孟加拉语（bn）有共享部分，但音系和声调差异大到难以互通——Glottolog 和 Ethnologue 视其为独立语言，而孟加拉国国家政策将其视为孟加拉语的地区变体。与边境对岸的罗兴亚语关系密切。'}, sources:[{type:'reference', title:'Glottolog: Chittagonian', url:'https://glottolog.org/resource/languoid/id/chit1276'}, {type:'reference', title:'Ethnologue: ctg', url:'https://www.ethnologue.com/language/ctg/'}] };
LANG_DATA['mag'].meta = { family:'Indo-Aryan (Eastern, Bihari)', speakers:'~18M', countries:'India (Bihar, Jharkhand)', official:'No (recognized scheduled)', script:'Devanagari / Kaithi (historical)', description:{en:'Magahi is the principal language of the Magadha region of southern Bihar, the historical center of ancient Indian empires (Maurya, Gupta). It is closely related to Bhojpuri and Maithili, all three sometimes grouped as Bihari.'} };
LANG_DATA['doi'].meta = { family:'Indo-Aryan (NW, Pahari/Punjabi-related)', speakers:'~2.6M', countries:'India (Jammu, Himachal Pradesh)', official:'India (8th Schedule)', script:'Devanagari / Dogra Akkhar (historical) / Perso-Arabic', description:{en:'Dogri is recognized as a constitutional language of India, primarily spoken in the Jammu region. Despite its small size, it has substantial literature and was added to the 8th Schedule in 2003.'} };
// LANG_DATA['mon'].meta removed Session 51 — see LANG_DATA['mnw'] below for canonical entry.
LANG_DATA['xkk'].meta = { family:'Austroasiatic (Mon-Khmer, Khmuic)', speakers:'~700K', countries:'Laos, Vietnam, Thailand, China', official:'No (recognized minority)', script:'Latin (multiple competing orthographies)', description:{en:'Khmu is the principal language of one of the largest minority groups in Laos. It is a register language using two phonation types (clear vs. breathy/tense) where many neighboring Tai-Kadai languages would use tone.'} };
LANG_DATA['moh'].meta = { family:'Iroquoian (Northern)', speakers:'~3.5K', countries:'Canada (Ontario, Quebec), USA (New York)', official:'No (recognized aboriginal)', script:'Latin (with apostrophes for glottal stop)', description:{en:'Mohawk (Kanien\'kéha) is one of the largest surviving Iroquoian languages, native to the Mohawk Valley. It is highly polysynthetic and has only 11 phonemes including 6 consonants. Active revitalization is ongoing in Akwesasne and Kahnawake.'} };
LANG_DATA['cho'].meta = { family:'Muskogean', speakers:'~10K', countries:'USA (Mississippi, Oklahoma)', official:'No (tribal recognition)', script:'Latin', description:{en:'Choctaw (Chahta anumpa) is the largest Muskogean language and was the basis for the Cherokee–Choctaw "Trail of Tears" trade jargon. The Choctaw Nation\'s school system has actively promoted the language since 1819.'} };
// Muscogee (Creek) — Muskogean, Oklahoma + Florida (Seminole), sister to Choctaw (cho).
LANG_DATA['mus'].meta = { family:'Muskogean (Eastern)', speakers:'~4K', countries:'USA (Oklahoma — Muscogee Nation; Florida — Seminole Tribe)', official:'No (Muscogee Nation recognized; Seminole Tribe of Florida co-official with English)', script:'Latin', description:{en:'Muscogee (Mvskoke, also called Creek) is an Eastern Muskogean language of the Muscogee (Creek) Nation in Oklahoma and the Seminole peoples of Florida and Oklahoma. Closely related to Hitchiti-Mikasuki and more distantly to Choctaw (cho). Forcibly relocated from Alabama and Georgia during the Trail of Tears (1830s). Active revitalization through the Muscogee Nation Department of Languages and the Seminole Tribe\'s immersion preschool. Notable for its complex switch-reference verb morphology.',ja:'マスコギ語（Mvskoke、クリーク語とも）はオクラホマ州のマスコギ（クリーク）国およびフロリダ州とオクラホマ州のセミノール人の東マスコギー諸語の言語。ヒッチティ＝ミカスキ語と近縁で、より遠い関係にチョクトー語（cho）がある。1830年代の「涙の道」でアラバマ州・ジョージア州から強制移住させられた。マスコギ国言語局とセミノール部族のイマージョン就学前教育プログラムを通じた積極的な復興活動。複雑なスイッチ・リファレンス動詞形態で言語学的に注目される。',ko:'머스코기어(Mvskoke, 크리크어로도 불림)는 오클라호마의 머스코기(크리크) 국과 플로리다·오클라호마의 세미놀 사람들의 동부 머스코기 어파 언어이다. 히치티-미카수키어와 가까운 친족 관계이며, 더 먼 관계에 초크토어(cho)가 있다. 1830년대 "눈물의 길"에서 앨라배마와 조지아로부터 강제 이주되었다. 머스코기 국 언어부와 세미놀 부족의 몰입 유아교육 프로그램을 통한 적극적 부흥. 복잡한 스위치 참조 동사 형태로 언어학적으로 주목된다.',zh:'马斯科吉语（Mvskoke，又称克里克语）是俄克拉荷马州马斯科吉（克里克）民族和佛罗里达州、俄克拉荷马州的塞米诺尔人的东马斯科吉语。与希奇蒂-米卡苏基语关系密切，与乔克托语（cho）关系较远。1830 年代"眼泪之路"中从阿拉巴马州和佐治亚州被强制迁移。通过马斯科吉民族语言部和塞米诺尔部落的浸入式幼儿教育进行积极复兴。以复杂的转换参照动词形态在语言学上著称。',vi:'Tiếng Muscogee (Mvskoke, còn gọi là Creek) là ngôn ngữ Muskogee Đông của Quốc gia Muscogee (Creek) ở Oklahoma và các dân tộc Seminole tại Florida và Oklahoma. Gần gũi với Hitchiti-Mikasuki và xa hơn là Choctaw (cho). Bị di dời cưỡng bức khỏi Alabama và Georgia trong cuộc "Trail of Tears" (những năm 1830). Đang được phục hồi tích cực thông qua Bộ Ngôn ngữ của Quốc gia Muscogee và chương trình giáo dục đắm chìm sớm của bộ lạc Seminole. Nổi bật về mặt ngôn ngữ học nhờ hệ thống đánh dấu đối chiếu (switch-reference) trong động từ.',de:'Muscogee (Mvskoke, auch Creek) ist eine ostmuskogeische Sprache der Muscogee (Creek) Nation in Oklahoma und der Seminolen in Florida und Oklahoma. Eng verwandt mit Hitchiti-Mikasuki und entfernter mit Choctaw (cho). Während des Trail of Tears (1830er Jahre) gewaltsam aus Alabama und Georgia umgesiedelt. Aktive Revitalisierung durch das Sprachendepartement der Muscogee Nation und Immersionsprogramme der Seminolen für Kleinkinder. Linguistisch bekannt für komplexe Switch-Reference-Verbmorphologie.',fr:'Le muscogee (Mvskoke, aussi appelé creek) est une langue muskogéenne orientale de la Muscogee (Creek) Nation en Oklahoma et des peuples séminoles de Floride et d\'Oklahoma. Proche du hitchiti-mikasuki et plus éloigné du choctaw (cho). Déplacés de force d\'Alabama et de Géorgie lors de la « Piste des Larmes » (années 1830). Revitalisation active grâce au département des langues de la Muscogee Nation et aux programmes d\'immersion préscolaire de la tribu séminole. Linguistiquement remarquable par sa morphologie verbale complexe à switch-reference.'}, sources:[{type:'reference', title:'Glottolog: Muscogee', url:'https://glottolog.org/resource/languoid/id/cree1271'}, {type:'reference', title:'Ethnologue: mus', url:'https://www.ethnologue.com/language/mus/'}, {type:'reference', title:'Martin (2011) A Grammar of Creek (Muskogee)', url:'https://www.nebraskapress.unl.edu/'}] };
LANG_DATA['esu'].meta = { family:'Eskimo-Aleut (Yupik)', speakers:'~10K', countries:'USA (Alaska)', official:'Alaska (recognized)', script:'Latin', description:{en:'Central Alaskan Yupik is the largest Yupik language and one of the most-spoken Alaska Native languages. It is highly polysynthetic and has post-base verbal suffixes that can stack indefinitely, allowing single-word sentences.'} };
LANG_DATA['ipk'].meta = { family:'Eskimo-Aleut (Inuit)', speakers:'~2K', countries:'USA (Alaska, North Slope)', official:'Alaska (recognized)', script:'Latin (with ġ ġ ł ñ ŋ q)', description:{en:'Inupiaq is the Inuit language of Alaska, descending in a chain through Inuktitut to Greenlandic. It uses an extended Latin alphabet with several diacritics. The Iñupiat people are particularly known for whaling traditions reflected in vocabulary.'} };
// Aleut — sole surviving Aleut branch of Eskimo-Aleut family, severely endangered.
LANG_DATA['ale'].meta = { family:'Eskimo-Aleut (Aleut)', speakers:'~150 (severely endangered)', countries:'USA (Alaska — Aleutian/Pribilof Islands), Russia (Commander Islands)', official:'Alaska (recognized indigenous)', script:'Cyrillic (Russia) / Latin (Alaska, post-1972 standard)', description:{en:'Aleut (Унаӈан тунуу / Unangam Tunuu) is the sole surviving Aleut branch of the Eskimo-Aleut family, sister to all Eskimo (Inuit + Yupik) languages. Speakers split between Alaska\'s Aleutian and Pribilof Islands and Russia\'s Commander Islands (Bering and Mednyj). Atka and Eastern dialect standards differ; the data shown here uses the Eastern standard. Mednyj Aleut on Bering Island is a unique mixed Aleut-Russian language.',ja:'アレウト語（Унаӈан тунуу / Unangam Tunuu）はエスキモー・アレウト語族で唯一現存するアレウト語派であり、すべてのエスキモー諸語（イヌイット＋ユピック）と姉妹関係にある。話者はアラスカのアリューシャン列島およびプリビロフ諸島と、ロシアのコマンドル諸島（ベーリング島・メドニー島）に分散する。アトカ方言と東部方言で標準が異なり、このデータは東部標準を採用。ベーリング島のメドニー・アレウト語は独特なアレウト・ロシア語混合言語である。',ko:'알류트어(Унаӈан тунуу / Unangam Tunuu)는 에스키모-알류트 어족에서 현존하는 유일한 알류트 어파이며, 모든 에스키모 언어(이누이트 + 유픽)와 자매 관계이다. 화자는 알래스카의 알류산 열도와 프리빌로프 제도, 러시아의 코만도르 제도(베링섬과 메드니섬)에 분산되어 있다. 아트카와 동부 방언의 표준이 다르며, 본 자료는 동부 표준을 사용한다. 베링섬의 메드니 알류트어는 알류트-러시아어가 혼합된 독특한 언어이다.',zh:'阿留申语（Унаӈан тунуу / Unangam Tunuu）是爱斯基摩-阿留申语系中唯一现存的阿留申语支，是所有爱斯基摩诸语（因纽特+尤皮克）的姊妹分支。说者分布于阿拉斯加阿留申群岛与普里比洛夫群岛，以及俄罗斯科曼多尔群岛（白令岛和梅德内岛）。阿特卡方言与东部方言标准不同，本数据使用东部标准。白令岛的梅德内阿留申语是独特的阿留申-俄语混合语言。'}, sources:[{type:'reference', title:'Glottolog: Aleut', url:'https://glottolog.org/resource/languoid/id/aleu1260'}, {type:'reference', title:'Ethnologue: ale', url:'https://www.ethnologue.com/language/ale/'}, {type:'reference', title:'Bergsland (1994) Aleut Dictionary', url:'https://uaf.edu/anla/'}] };
LANG_DATA['apw'].meta = { family:'Na-Dené (Athabaskan, Southern)', speakers:'~14K', countries:'USA (Arizona)', official:'No (tribal recognition)', script:'Latin (with diacritic tones)', description:{en:'Western Apache is one of the largest Athabaskan languages, closely related to Navajo. It uses a complex tone system marked with acute accents and has consonant inventory featuring lateral fricatives ɬ and ejective stops.'} };
LANG_DATA['dak'].meta = { family:'Siouan', speakers:'~290 (active)', countries:'USA (Minnesota, Dakotas, Nebraska), Canada', official:'No (tribal recognition)', script:'Latin (with č š ŋ ȟ accents)', description:{en:'Dakota is the eastern Sioux language, closely related to Lakota (the major sound difference is /d/ in Dakota vs. /l/ in Lakota for the same words). The Santee, Sisseton, Wahpeton, and Yankton-Yanktonai dialects are grouped here.'} };
LANG_DATA['chy'].meta = { family:'Algic (Algonquian)', speakers:'~2K', countries:'USA (Montana, Oklahoma)', official:'No (tribal recognition)', script:'Latin (with ė ô high pitches and \' for glottal stop)', description:{en:'Cheyenne (Tsêhésenêstsestôtse) is an Algonquian language with a 4-tone system (high, mid, low, voiceless) — unusual for Algonquian. Words are typically very long due to polysynthesis with abundant prefixes.'} };

