LANG_DATA['pms'].meta = { family:'Romance (Gallo-Italic)', speakers:'~2M', countries:'Italy (Piedmont)', official:'No (recognized regional)', script:'Latin (with ö ò è ù)', description:{en:'Piedmontese (Piemontèis) is the Gallo-Italic language of Piedmont. Closer to Occitan and French than to standard Italian, it has a literary tradition since the 13th century. The 2004 Piedmont regional law recognizes it as the language of the territory.'} };
LANG_DATA['eml'].meta = { family:'Romance (Gallo-Italic)', speakers:'~2M', countries:'Italy (Emilia-Romagna)', official:'No (regional)', script:'Latin', description:{en:'Emilian-Romagnol covers two related Gallo-Italic varieties (Emilian and Romagnol) of the Po Valley. They share many features with neighboring Lombard and Piedmontese, marking them as part of the broader Gallo-Italic group.'} };
LANG_DATA['mwl'].meta = { family:'Romance (Iberian, Astur-Leonese)', speakers:'~7-15K', countries:'Portugal (Miranda do Douro)', official:'Portugal (recognized 1999)', script:'Latin', description:{en:'Mirandese is the only minority language with official recognition in Portugal. Linguistically it is part of the Astur-Leonese group (closer to Asturian than to Portuguese), having survived in the Miranda do Douro region near the Spanish border.'} };
LANG_DATA['pnt'].meta = { family:'Hellenic', speakers:'~600K', countries:'Greece, Russia, Turkey, Georgia (diaspora)', official:'No (recognized minority)', script:'Greek', description:{en:'Pontic Greek descends from the medieval Greek of the Pontus region (south Black Sea coast). The 1923 Greek-Turkish population exchange relocated most speakers to Greece. It preserves several archaic features lost in Modern Greek.'} };
LANG_DATA['hno'].meta = { family:'Indo-Aryan (NW, Lahnda)', speakers:'~5M', countries:'Pakistan (Khyber Pakhtunkhwa, Punjab)', official:'No (regional)', script:'Perso-Arabic', description:{en:'Hindko is a Lahnda group Indo-Aryan language closely related to Punjabi and Saraiki. It is spoken by ethnic Hindkowans across Pakistan\'s northwest, often as a second language alongside Pashto in mixed areas.'} };
