LANG_DATA['gv'].meta = { family:'Indo-European (Celtic, Goidelic)', speakers:'~2K (revived)', countries:'Isle of Man (UK Crown Dependency)', official:'Isle of Man', script:'Latin', description:{en:'Manx (Gaelg) was once considered extinct (last native speaker died 1974), but has been successfully revitalized — with several hundred fluent speakers and a Manx-medium school. Closely related to Irish and Scottish Gaelic, it preserves several Goidelic features lost elsewhere.'} };
