LANG_DATA['mns'].meta = { family:'Uralic (Ob-Ugric)', speakers:'~940', countries:'Russia (Khanty-Mansi AO)', official:'Khanty-Mansi Autonomous Okrug (recognized)', script:'Cyrillic', description:{en:'Mansi (formerly "Vogul") is the closer relative of Hungarian than Khanty is, despite the small modern speaker base. The Mansi-Khanty-Hungarian connection (Ugric branch of Uralic) is one of historical linguistics\' classic long-distance discoveries.'} };
