LANG_DATA['tmh'] && (LANG_DATA['tmh'].meta = { family:'Afro-Asiatic (Berber, Tuareg)', speakers:'~1.6M (across Tuareg varieties)', speakerSource:'Ethnologue 27', speakerYear:2024, iso6393:'tmh', countries:'Algeria, Mali, Niger, Burkina Faso, Libya', official:'Tamazight co-official in Algeria (2016); national language in Mali/Niger', script:'Tifinagh (traditional); Latin and Arabic also used', description:{en:'Tamasheq (Tuareg) is the Berber language of the central Sahara, written in the indigenous Tifinagh script. The Tahaggart variety of southern Algeria/Niger preserves conservative Berber phonology including pharyngealized consonants. The Tuareg confederations maintain a distinct nomadic literary culture.'} });
LANG_DATA['ng'].meta = { family:'Atlantic-Congo (Bantu, R10)', speakers:'~600K', countries:'Namibia, Angola', official:'Namibia (national)', script:'Latin', description:{en:'Ndonga (Oshindonga) is one of two main standard varieties of Oshiwambo (with Kwanyama). It is the more widely written variety and is taught in Namibian schools as a national language.'} };
// Kuanyama / Oshikwanyama — Bantu R21, sister to Ndonga (ng) within Oshiwambo cluster. Cross-border Namibia/Angola.
LANG_DATA['kj'].meta = { family:'Atlantic-Congo (Bantu, R21 — Oshiwambo)', speakers:'~280K', countries:'Namibia (north-central), Angola (Cunene Province)', official:'Namibia (national language); Angola (recognised regional)', script:'Latin', description:{en:'Kuanyama / Oshikwanyama is the second main standard variety of Oshiwambo (with Ndonga, ng), used by the Ovakwanyama people of north-central Namibia and Cunene Province in Angola. It crosses the colonial-era Namibia-Angola border because the boundary cut through traditional Ovakwanyama lands. The two Oshiwambo varieties (Kuanyama + Ndonga) are mutually intelligible but standardised separately, with Kuanyama having a stronger southern Angola presence and Ndonga dominating in Namibia.',ja:'クワニヤマ語／オシクワニヤマ語はオシワンボ語のもう一つの主要標準変種（もう一つはンドンガ語 ng）で、ナミビア中北部とアンゴラのクネネ州のオヴァクワニヤマ人によって使用される。植民地時代のナミビア・アンゴラ国境が伝統的オヴァクワニヤマの土地を分断したため、国境をまたいでいる。クワニヤマとンドンガは相互理解可能だが別々に標準化され、クワニヤマはアンゴラ南部での存在感が強く、ンドンガはナミビアで優勢である。',ko:'콰니야마어/오시콰니야마어는 오시왐보어의 또 다른 주요 표준 변종(다른 하나는 은동가어 ng)이며, 나미비아 중북부와 앙골라 쿠네네 주의 오바콰니야마인들이 사용한다. 식민지 시대의 나미비아-앙골라 국경이 전통적 오바콰니야마 영토를 가로질러 자른 결과 국경을 넘나든다. 콰니야마어와 은동가어는 상호 이해 가능하지만 별도로 표준화되었으며, 콰니야마어는 앙골라 남부에서 더 강세이고 은동가어는 나미비아에서 우세하다.',zh:'夸尼亚马语／奥希夸尼亚马语是奥希万博语的另一种主要标准变体（另一种是恩东加语 ng），由纳米比亚中北部和安哥拉库内内省的奥瓦夸尼亚马人使用。由于殖民时代纳米比亚-安哥拉边界穿过传统奥瓦夸尼亚马领地，因此跨境分布。夸尼亚马语与恩东加语可互通但分别标准化；夸尼亚马语在安哥拉南部存在感更强，恩东加语在纳米比亚占优势。',vi:'Tiếng Kuanyama / Oshikwanyama là biến thể chuẩn chính thứ hai của Oshiwambo (cùng với Ndonga, ng), được người Ovakwanyama ở miền bắc-trung Namibia và tỉnh Cunene của Angola sử dụng. Nó vắt qua biên giới Namibia-Angola thời thuộc địa vì đường biên giới đã cắt ngang lãnh thổ truyền thống của người Ovakwanyama. Hai biến thể Oshiwambo (Kuanyama + Ndonga) có thể hiểu lẫn nhau nhưng được chuẩn hóa riêng biệt, trong đó Kuanyama có sự hiện diện mạnh hơn ở miền nam Angola và Ndonga chiếm ưu thế tại Namibia.',de:'Kuanyama / Oshikwanyama ist die zweite große Standardvarietät des Oshiwambo (neben Ndonga, ng), die von den Ovakwanyama im nördlichen Zentral-Namibia und in der angolanischen Provinz Cunene gesprochen wird. Sie überschreitet die kolonialzeitliche Grenze zwischen Namibia und Angola, weil diese Grenze das traditionelle Ovakwanyama-Gebiet zerschnitt. Die beiden Oshiwambo-Varietäten (Kuanyama + Ndonga) sind gegenseitig verständlich, werden aber getrennt standardisiert; Kuanyama ist im Süden Angolas stärker präsent, Ndonga dominiert in Namibia.',fr:'Le kuanyama / oshikwanyama est la seconde grande variété standard de l\'oshiwambo (avec le ndonga, ng), parlée par les Ovakwanyama du centre-nord de la Namibie et de la province de Cunene en Angola. Elle traverse la frontière coloniale Namibie-Angola parce que celle-ci coupait à travers les terres traditionnelles ovakwanyama. Les deux variétés oshiwambo (kuanyama + ndonga) sont mutuellement intelligibles mais standardisées séparément; le kuanyama est plus présent au sud de l\'Angola, le ndonga domine en Namibie.'}, sources:[{type:'reference', title:'Glottolog: Kwanyama', url:'https://glottolog.org/resource/languoid/id/kuan1252'}, {type:'reference', title:'Ethnologue: kua', url:'https://www.ethnologue.com/language/kua/'}, {type:'reference', title:'Tobias & Turvey (1976) English-Kwanyama dictionary', url:'https://www.archive.org/'}] };
LANG_DATA['umb'].meta = { family:'Atlantic-Congo (Bantu, R10)', speakers:'~6M', countries:'Angola', official:'Angola (national)', script:'Latin', description:{en:'Umbundu is the largest indigenous language of Angola, native to the central plateau (Bie province). It serves as a major regional lingua franca and was an important language of trade with the Portuguese empire.'} };
LANG_DATA['kmb'].meta = { family:'Atlantic-Congo (Bantu, H21)', speakers:'~3M', countries:'Angola', official:'Angola (national)', script:'Latin', description:{en:'Kimbundu is the second-largest indigenous language of Angola, spoken in the Luanda region. It contributed many words to Brazilian Portuguese (and through it to other languages) including the word "samba" and "dengue".'} };
// Luvale — Bantu K14, ~600K, Angola/Zambia. National language of Zambia + recognized regional in Angola.
LANG_DATA['lue'].meta = { family:'Atlantic-Congo (Bantu, K14)', speakers:'~600K', countries:'Zambia (North-Western Province), Angola (Moxico Province)', official:'Zambia (one of 7 official Bantu languages)', script:'Latin', description:{en:'Luvale (Chiluvale) is a Bantu K language spoken in the Angola-Zambia borderlands. The Luvale people are one of the seven recognized "Bantu of Zambia" official-language groups. The language has tone and Bantu noun-class agreement and is closely related to Lunda (lun) within the K14 group. Notable for the Likumbi Lya Mize cultural festival and the makishi masquerade tradition (UNESCO Intangible Heritage 2008).',ja:'ルヴァレ語（Chiluvale）はアンゴラ・ザンビア国境地帯で話されるバントゥーK言語。ルヴァレ人はザンビアで承認されている7つの「ザンビアのバントゥー」公用語グループの一つ。声調とバントゥー名詞クラス一致を持ち、K14グループ内でルンダ語（lun）と近縁。リクンビ・リャ・ミゼ文化祭やマキシ仮面舞踏伝統（UNESCO無形遺産2008年）でも知られる。',ko:'루발레어(Chiluvale)는 앙골라-잠비아 국경 지역에서 사용되는 반투 K 언어이다. 루발레인은 잠비아에서 인정된 "잠비아의 반투" 7개 공용어 그룹 중 하나이다. 성조와 반투 명사 부류 일치를 가지며, K14 그룹 내에서 룬다어(lun)와 가까운 친족 관계이다. 리쿰비 랴 미제 문화제와 마키시 가면극 전통(UNESCO 무형유산 2008)으로 알려져 있다.',zh:'卢瓦莱语（Chiluvale）是安哥拉-赞比亚边境地区使用的班图 K 类语言。卢瓦莱人是赞比亚承认的"赞比亚的班图"7 种官方语言群体之一。具有声调和班图名词类一致，在 K14 组内与隆达语（lun）关系密切。以利昆比·利亚·米泽文化节和马基希假面舞蹈传统（UNESCO 非物质遗产 2008）著称。'}, sources:[{type:'reference', title:'Glottolog: Luvale', url:'https://glottolog.org/resource/languoid/id/luva1239'}, {type:'reference', title:'Ethnologue: lue', url:'https://www.ethnologue.com/language/lue/'}, {type:'reference', title:'Horton (1949) A Grammar of Luvale', url:'https://www.archive.org/'}] };
LANG_DATA['her'].meta = { family:'Atlantic-Congo (Bantu, R31)', speakers:'~250K', countries:'Namibia, Botswana, Angola', official:'Namibia (national)', script:'Latin', description:{en:'Herero (Otjiherero) is the language of the Herero people of central and northern Namibia. The Herero genocide of 1904-1908 by German colonial forces is one of the earliest cases of state-sponsored genocide in the 20th century.'} };
LANG_DATA['xal'].meta = { family:'Mongolic (Western, Oirat)', speakers:'~80K', countries:'Russia (Kalmykia)', official:'Republic of Kalmykia', script:'Cyrillic / Clear Script (1648, historical)', description:{en:'Kalmyk is the European Mongolic language, descended from 17th-c. Oirat migrations to the lower Volga. The Clear Script (Todo bichig) was created in 1648 by Zaya Pandita; modern Kalmyk uses Cyrillic with extra letters һ, ң, ө, ү.'} };
LANG_DATA['sg'].meta = { family:'Niger-Congo (Adamawa-Ubangian)', speakers:'~5M (lingua franca, ~500K L1)', countries:'Central African Republic', official:'CAR (with French)', script:'Latin', description:{en:'Sango (Sängö) is the lingua franca of the Central African Republic, originating as a trade pidgin based on Northern Ngbandi during 19th-c. river commerce. It is one of the few African languages to function as both an official language and a creole-like lingua franca.'} };
LANG_DATA['toi'].meta = { family:'Atlantic-Congo (Bantu, M64)', speakers:'~1.7M', countries:'Zambia, Zimbabwe', official:'Zambia (regional)', script:'Latin', description:{en:'Tonga (Chitonga) of Zambia is distinct from Tongan of the Pacific despite the name. It is one of the major regional Zambian languages, spoken in the Southern and Western Provinces around Lake Kariba.'} };

// === Phase 4: Historical / Ancient Languages metadata ===
LANG_DATA['peo'].meta = { family:'Iranian (Old)', speakers:'Extinct (~550-330 BCE)', countries:'Achaemenid Persia (modern Iran/Iraq)', official:'Achaemenid Empire', script:'Old Persian cuneiform', description:{en:'Old Persian was the language of the Achaemenid Empire (c. 550-330 BCE), preserved in the trilingual royal inscriptions at Behistun and elsewhere. Its unique cuneiform syllabary, derived from but distinct from Akkadian cuneiform, was used almost exclusively for royal monumental inscriptions. It is the direct ancestor of Middle Persian and ultimately Modern Persian.'} };
LANG_DATA['ave'].meta = { family:'Iranian (Old)', speakers:'Extinct as L1; liturgical use in Zoroastrianism', countries:'Eastern Iran / Central Asia (origin)', official:'No (sacred liturgical)', script:'Avestan alphabet (Sasanian period)', description:{en:'Avestan is the sacred language of Zoroastrianism, preserved in the Avesta scriptures. Two stages exist: Old Avestan (the Gathas attributed to Zarathushtra, c. 1500-1000 BCE) and Younger Avestan (c. 700-300 BCE). The Avestan alphabet was developed in the Sasanian period to record orally transmitted liturgy.'} };
LANG_DATA['xto'].meta = { family:'Indo-European (Tocharian)', speakers:'Extinct (5th-10th c. CE)', countries:'Tarim Basin (modern Xinjiang, China)', official:'No', script:'Brahmi-derived Tocharian script', description:{en:'Tocharian A (Eastern Tocharian, sometimes called Agnean) is one of two extinct Indo-European languages of the Tarim Basin oases. Attested in Buddhist manuscripts, its discovery in the early 20th century revealed that Indo-European had reached the easternmost edge of Eurasia. It survives only in religious texts; Tocharian B has a wider corpus.'} };
LANG_DATA['txb'].meta = { family:'Indo-European (Tocharian)', speakers:'Extinct (5th-10th c. CE)', countries:'Tarim Basin (modern Xinjiang)', official:'No', script:'Brahmi-derived Tocharian script', description:{en:'Tocharian B (Western Tocharian, Kuchean) is the more widely attested Tocharian language, with both religious and secular documents from the Buddhist kingdom of Kucha. Both Tocharian languages went extinct by 1000 CE as Turkic peoples (Uyghurs) replaced them in the region.'} };
LANG_DATA['phn'].meta = { family:'Afro-Asiatic (Northwest Semitic, Canaanite)', speakers:'Extinct (~1500 BCE-3rd c. CE)', countries:'Phoenicia (Lebanon, coastal Syria/Israel) + Mediterranean colonies', official:'Phoenician city-states (Tyre, Sidon, Byblos, Carthage)', script:'Phoenician alphabet (𐤀𐤁𐤂)', description:{en:'Phoenician was the Northwest Semitic language of the Phoenician city-states from c. 1500 BCE. The 22-letter Phoenician alphabet is the direct or indirect ancestor of nearly all modern alphabets — Greek, Latin, Cyrillic, Hebrew, Aramaic, Arabic, and South Asian Brahmic scripts. Punic was its late variant in Carthage.'} };
LANG_DATA['uga'].meta = { family:'Afro-Asiatic (Northwest Semitic)', speakers:'Extinct (~1400-1180 BCE)', countries:'Ugarit (Bronze Age coastal Syria)', official:'Kingdom of Ugarit', script:'Ugaritic alphabetic cuneiform (30 signs)', description:{en:'Ugaritic was a Northwest Semitic language at the Bronze Age city of Ugarit (modern Ras Shamra, Syria), c. 14th-12th centuries BCE. Its cuneiform alphabet of 30 signs is the earliest documented true alphabet (preceding Phoenician), and the Ugaritic mythological texts (Baal Cycle) provide essential cultural context for understanding the Hebrew Bible.'} };
LANG_DATA['xlu'].meta = { family:'Indo-European (Anatolian)', speakers:'Extinct (~2000-700 BCE)', countries:'Anatolia (modern Turkey)', official:'Hittite Empire (co-language)', script:'Cuneiform (Bronze Age) / Anatolian hieroglyphs (Iron Age)', description:{en:'Luwian was an Anatolian language closely related to Hittite, with two attestation traditions: cuneiform Luwian on Bronze Age clay tablets from Hattusa, and hieroglyphic Luwian on Iron Age stone monuments using the iconic Anatolian hieroglyphs. After the fall of Hattusa (~1180 BCE), Luwian outlived Hittite by several centuries.'} };
LANG_DATA['pal'].meta = { family:'Iranian (Middle)', speakers:'Extinct as L1; Zoroastrian liturgical', countries:'Sasanian Empire (Iran, Iraq, parts of Central Asia)', official:'Sasanian Empire (224-651 CE)', script:'Pahlavi script (Inscriptional and Book varieties)', description:{en:'Middle Persian (Pahlavi) was the official language of the Sasanian Empire and the bridge between Old Persian and Modern Persian. After the Arab conquest, it remained the liturgical and scholarly language of Zoroastrian communities. The Pahlavi script is a logographic-and-Aramaic-derived system notoriously difficult to read.'} };
LANG_DATA['syc'].meta = { family:'Afro-Asiatic (Semitic, Aramaic, Eastern)', speakers:'Liturgical (~10K active liturgical use)', countries:'Originally Edessa (modern Şanlıurfa, Turkey)', official:'Eastern Christian liturgical language', script:'Syriac (Estrangela / Serto / Madnhāyā)', description:{en:'Classical Syriac is a literary Aramaic language that flourished as the lingua franca of Eastern Christianity from the 2nd-13th centuries CE, centered on Edessa. It produced one of antiquity\'s greatest theological, philosophical, and scientific corpora, and remains the liturgical language of the Syriac Orthodox Church, Assyrian Church of the East, and others.'} };
LANG_DATA['fro'].meta = { family:'Romance (Gallo-Romance)', speakers:'Extinct (~800-1340 CE)', countries:'Northern France', official:'Capetian France (selectively)', script:'Latin', description:{en:'Old French (françois, romanz) is the form of French from c. 800-1340 CE in northern France. It is the language of the Chanson de Roland, the Roman de la Rose, Marie de France\'s Lais, and Chrétien de Troyes\'s Arthurian romances. It preserved a two-case system (subject/oblique) lost in Middle French.'} };
LANG_DATA['goh'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~750-1050 CE)', countries:'Germany, Austria, Switzerland (Alemannic, Bavarian, Franconian)', official:'Frankish Empire (selectively)', script:'Latin', description:{en:'Old High German is the earliest stage of High German (c. 750-1050 CE), distinguished from neighboring West Germanic languages by the High German consonant shift (e.g., t → z/ts, p → pf/f, k → ch). Major literary texts include the Lay of Hildebrand (Hildebrandslied) and Otfrid of Weissenburg\'s Evangelienbuch.'} };
LANG_DATA['gez'].meta = { family:'Afro-Asiatic (Semitic, South, Ethiopic)', speakers:'Liturgical (no L1); Ethiopian/Eritrean Orthodox liturgy', countries:'Originally Aksum (modern northern Ethiopia/Eritrea)', official:'Ethiopian/Eritrean Orthodox Tewahedo Churches', script:'Ge\'ez script (Ethiopic abugida) ግዕዝ', description:{en:'Ge\'ez (Classical Ethiopic) is a South Semitic language that served as the literary and royal language of the Ethiopian Empire from c. 4th century CE. It is the parent of Tigrinya, Tigre, and Amharic. The Ge\'ez script is still actively used for those three modern languages, and Ge\'ez itself remains the liturgical language of the Ethiopian and Eritrean Orthodox Tewahedo Churches.'} };

// === Phase 4B: more Historical / Ancient Languages metadata ===
LANG_DATA['gmy'].meta = { family:'Indo-European (Hellenic, pre-classical)', speakers:'Extinct (~1450-1200 BCE)', countries:'Mycenaean Greece (Aegean)', official:'Bronze Age palace administrations', script:'Linear B syllabary (~90 syllabic + 100+ ideograms)', description:{en:'Mycenaean Greek is the earliest attested form of Greek, recorded in the Linear B syllabary on Bronze Age clay tablets at Knossos, Pylos, Mycenae, and other palace sites. Its decipherment by Michael Ventris in 1952 proved that Greek-speakers were already in Greece in the Bronze Age. Vocabulary attested in Linear B is mostly administrative; many basic words must be reconstructed via Classical Greek.'} };
LANG_DATA['xct'].meta = { family:'Sino-Tibetan (Tibeto-Burman, Bodish)', speakers:'Liturgical (Tibetan Buddhism)', countries:'Tibet (originally), China, Mongolia, India, Bhutan, Nepal', official:'Tibetan Buddhist liturgical language', script:'Tibetan (Uchen) ྑ', description:{en:'Classical Tibetan refers to the literary form of Tibetan from c. 7th-12th centuries CE, used for the translation of the Buddhist canon (Kangyur and Tengyur) and indigenous Tibetan literature. Its orthography preserves features of Old Tibetan that have been radically altered in modern spoken Tibetan. It remains the liturgical language of Tibetan Buddhism.'} };
LANG_DATA['xpu'].meta = { family:'Afro-Asiatic (Northwest Semitic, Canaanite)', speakers:'Extinct (~800 BCE-5th c. CE)', countries:'Carthage and the Punic Mediterranean (Tunisia, Sardinia, Sicily, Malta, etc.)', official:'Carthaginian Empire', script:'Punic alphabet (cursive Phoenician)', description:{en:'Punic was the late variety of Phoenician spoken across the Carthaginian commercial empire and its successor states. After Roman conquest, it persisted as a regional language in North Africa for centuries, with Augustine of Hippo (5th c. CE) attesting to ongoing Punic usage. Neo-Punic developed cursive script forms.'} };
LANG_DATA['xhu'].meta = { family:'Hurro-Urartian (separate from IE/Semitic)', speakers:'Extinct (~2300-1000 BCE)', countries:'Mitanni and northern Mesopotamia (modern N Iraq, Syria, SE Turkey)', official:'Mitanni kingdom', script:'Cuneiform', description:{en:'Hurrian was a major Near Eastern language of the 3rd-2nd millennia BCE, used as the lingua franca of the Mitanni kingdom and known from cuneiform tablets at Yorgan Tepe (Nuzi), Bogazköy, and elsewhere. Together with Urartian (a sister language), it forms the Hurro-Urartian family, with no proven relations to other languages — possibly a Caucasian connection has been proposed.'} };
LANG_DATA['elx'].meta = { family:'Language isolate (Elamite)', speakers:'Extinct (~2700-300 BCE)', countries:'Elam (modern southwestern Iran)', official:'Elamite Empire, Achaemenid administration', script:'Elamite cuneiform / Linear Elamite (undeciphered earlier form)', description:{en:'Elamite is a poorly classified language of ancient southwestern Iran, attested for over 2,000 years. The Achaemenid Persians used Elamite as one of their three administrative languages (alongside Old Persian and Akkadian). The earlier Linear Elamite script was largely undeciphered until partial readings were proposed in 2020.'} };
LANG_DATA['xsa'].meta = { family:'Afro-Asiatic (Semitic, South, Old South Arabian)', speakers:'Extinct (~1000 BCE-600 CE)', countries:'Sabaean kingdom (modern Yemen, southwestern Arabia)', official:'Sabaean and Himyarite kingdoms', script:'Old South Arabian script (Musnad, 𐩠𐩡𐩢𐩣)', description:{en:'Sabaean is the most-attested Old South Arabian language, used in tens of thousands of inscriptions across ancient Yemen, especially around the Marib dam. The Musnad script (also called Old South Arabian) is the ancestor of Ge\'ez script, transmitted via early Aksumite contact across the Red Sea.'} };
LANG_DATA['kaw'].meta = { family:'Austronesian (Malayo-Polynesian, Javanic)', speakers:'Extinct as L1; literary (Hindu-Buddhist scholarly use in Bali)', countries:'Java, Bali (Hindu-Buddhist period)', official:'Javanese Hindu-Buddhist kingdoms (Mataram, Majapahit)', script:'Kawi script (ancestor of Balinese, Javanese, Lontara)', description:{en:'Old Javanese (Kawi) is the form of Javanese used in literary and religious texts from the 9th to 15th centuries CE. It is heavily influenced by Sanskrit, with much philosophical, religious, and learned vocabulary borrowed directly. The Kawi script (Hanacaraka ancestor) is the source of all later Indonesian Brahmic scripts. Kawi continues in ceremonial use in Bali.'} };
LANG_DATA['kho'].meta = { family:'Iranian (Saka)', speakers:'Extinct (~5th-10th c. CE)', countries:'Khotan (Tarim Basin, modern Xinjiang)', official:'Buddhist kingdom of Khotan', script:'Brahmi-derived Khotanese script', description:{en:'Khotanese (also called Khotanese Saka) is a Middle Iranian language of the eastern Saka group, attested in Buddhist manuscripts from the kingdom of Khotan on the southern Silk Road. It is closely related to Tumshuqese (also Saka) and more distantly to Sogdian and other Eastern Iranian languages. Like Tocharian, it disappeared as Turkic peoples occupied the Tarim Basin.'} };
LANG_DATA['gmh'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~1050-1350 CE)', countries:'Germany, Austria, Switzerland (medieval)', official:'Holy Roman Empire (selectively)', script:'Latin', description:{en:'Middle High German is the form of High German between Old High German and Early New High German. It is the language of the Nibelungenlied, the Minnesänger (especially Walter von der Vogelweide), Wolfram von Eschenbach\'s Parzival, and Gottfried von Strassburg\'s Tristan. The High German consonant shift was complete by the Middle High German period.'} };
LANG_DATA['osp'].meta = { family:'Romance (Iberian)', speakers:'Extinct (~10th c. - early 16th c.)', countries:'Castile, León, Spain (medieval)', official:'Kingdom of Castile (selectively)', script:'Latin', description:{en:'Old Spanish (Castilian) is the form of Spanish from c. 1000 to early 1500s, characterized by complex sibilant systems (𐌽 ts/dz, š/ž, s/z) that simplified into Modern Spanish during the early modern period. Major works include the Cantar de Mio Cid (12th c.), Alfonso X\'s legal and scientific texts, and the Libro de buen amor of Juan Ruiz.'} };
LANG_DATA['okz'].meta = { family:'Austroasiatic (Mon-Khmer)', speakers:'Extinct (~7th-15th c. CE)', countries:'Khmer Empire (modern Cambodia, Thailand, Laos, Vietnam)', official:'Khmer Empire (Angkor)', script:'Old Khmer script (ancestor of modern Khmer script)', description:{en:'Old Khmer is the form of Khmer attested in inscriptions from the 7th-15th centuries CE, especially during the Khmer Empire centered on Angkor. Inscriptions on stone temples document royal grants, religious foundations, and administrative matters. The Old Khmer script is a direct ancestor of modern Khmer script and was a major influence on Thai and Lao scripts.'} };
LANG_DATA['osx'].meta = { family:'Indo-European (Germanic, West)', speakers:'Extinct (~750-1100 CE)', countries:'Westphalia, Lower Saxony (modern northern Germany)', official:'Saxon territories (selectively)', script:'Latin', description:{en:'Old Saxon (Old Low German) is the earliest documented form of Low German, distinguished from Old High German by lacking the High German consonant shift. The most important Old Saxon text is the Heliand (c. 830 CE), a 6,000-line alliterative epic retelling of the Gospel narrative — one of the longest poems in any early Germanic language.'} };

// === Phase 5 metadata ===
LANG_DATA['smg'].meta = { family:'Atlantic-Congo (Bantu)', speakers:'~10M', countries:'Tanzania', official:'No (regional)', script:'Latin', disambiguator:{en:'(legacy ISO smg code carrying Sukuma data; suk is the canonical row — cleanup pending)',ja:'（旧 ISO smg コードに格納されたスクマ語データ；suk が正式行 — 整理予定）',ko:'(레거시 ISO smg 코드에 담긴 수쿠마어 데이터; suk가 공식 행 — 정리 예정)',zh:'（旧 ISO smg 代码携带的苏库马语数据；suk 为正式条目 — 待清理）'}, description:{en:'Sukuma is the most spoken indigenous language of Tanzania, native to the southern shore of Lake Victoria. Despite its large speaker base, it is not used in official contexts in favor of Swahili. It has 9 noun classes and a tonal system.'} };
LANG_DATA['mos'].meta = { family:'Niger-Congo (Gur)', speakers:'~7M', countries:'Burkina Faso, Côte d\'Ivoire, Ghana, Togo', official:'Burkina Faso (national)', script:'Latin (with ɛ ɔ ɩ ʊ)', description:{en:'Mooré (Mossi) is the principal language of Burkina Faso, spoken by the Mossi people who form about 50% of the country\'s population. It is a Gur language with two phonemic tones and characteristic ATR vowel harmony with the special letters ɛ ɔ ɩ ʊ.'} };
LANG_DATA['kln'].meta = { family:'Nilo-Saharan (Eastern Nilotic)', speakers:'~5M', countries:'Kenya, Uganda, Tanzania', official:'Kenya (recognized)', script:'Latin', description:{en:'Kalenjin is a macrolanguage covering several mutually intelligible Highland Nilotic varieties of Kenya\'s Rift Valley (Kipsigis, Nandi, Tugen, etc.). Kalenjin athletes have long dominated middle and long-distance running.'} };
LANG_DATA['mfe'].meta = { family:'French-based creole', speakers:'~1.3M', countries:'Mauritius, Réunion, Seychelles', official:'Mauritius (de facto national)', script:'Latin', description:{en:'Mauritian Creole is the de facto national language of Mauritius, derived from 18th-century French during the colonial period. It has standardized orthography (Lortograf-larmoni 2011) and adopts a phonemic spelling rather than French historical spellings.'} };
LANG_DATA['mnk'].meta = { family:'Niger-Congo (Mande, Manding)', speakers:'~1.5M', countries:'Senegal, Gambia, Guinea-Bissau, Mali', official:'No (recognized regional)', script:'Latin / Arabic / N\'Ko', description:{en:'Mandinka is one of the principal Mande languages of Senegambia, descending in unbroken continuity from the language of the medieval Mali Empire. With Bambara and Dyula, it forms the Manding dialect continuum, with which it is often mutually intelligible.'} };
LANG_DATA['bqi'].meta = { family:'Iranian (Southwestern, Lurish)', speakers:'~1M', countries:'Iran (Bakhtiari region)', official:'No', script:'Perso-Arabic', description:{en:'Bakhtiari is a Lurish/Lori-related Iranian language spoken by the semi-nomadic Bakhtiari people of southwestern Iran. It is sometimes classified as a major dialect of Lurish but has enough divergence to be considered separately by SIL.'} };
LANG_DATA['unr'].meta = { family:'Austroasiatic (Munda)', speakers:'~1.6M', countries:'India (Jharkhand, Odisha, West Bengal)', official:'No (recognized scheduled)', script:'Devanagari / Latin / Ol Chiki', description:{en:'Mundari is the second-largest Munda language after Santali, native to the Chota Nagpur Plateau. It is the language of the Munda people, after whom the Munda branch of Austroasiatic is named.'} };
LANG_DATA['hoc'].meta = { family:'Austroasiatic (Munda)', speakers:'~1.4M', countries:'India (Jharkhand, Odisha)', official:'No (recognized scheduled)', script:'Warang Citi (𑣁) / Devanagari / Latin', description:{en:'Ho is a Munda language closely related to Mundari, native to the Singhbhum region. It is unique in having its own indigenous script — Warang Citi, invented by Lako Bodra in the early 20th century, encoded in Unicode block U+118A0–U+118FF.'} };
LANG_DATA['enq'].meta = { family:'Trans-New Guinea (Engan)', speakers:'~230K', countries:'Papua New Guinea (Enga Province)', official:'No (recognized regional)', script:'Latin', description:{en:'Enga is the most spoken language of Papua New Guinea\'s highlands and the largest Papuan (non-Austronesian) language. It is the principal language of Enga Province and reflects the linguistic diversity of New Guinea — one of the world\'s most linguistically diverse regions.'} };
LANG_DATA['xpr'].meta = { family:'Iranian (Middle, Northwest)', speakers:'Extinct (~250 BCE-3rd c. CE)', countries:'Parthian Empire (Iran, Iraq, Central Asia)', official:'Parthian Empire', script:'Parthian script (Aramaic-derived)', description:{en:'Parthian was the language of the Parthian Empire (Arsacid dynasty, 247 BCE-224 CE) and a major Middle Iranian language alongside Middle Persian (Pahlavi). It used the Parthian script (a development of Imperial Aramaic) and was eventually replaced by Pahlavi when the Sasanian dynasty took power.'} };
LANG_DATA['xqa'].meta = { family:'Turkic (Karluk)', speakers:'Extinct (~9th-13th c. CE)', countries:'Karakhanid Khanate (Central Asia, modern Xinjiang/Kyrgyzstan/Uzbekistan)', official:'Karakhanid Khanate', script:'Arabic / Old Uyghur', description:{en:'Karakhanid (also called Old Uyghur or Khaqani Turkic) is the literary Turkic language of the 11th-13th centuries, attested in Mahmud al-Kashgari\'s Diwan Lughat al-Turk (1072) — one of the earliest comparative dictionaries — and Yusuf Khass Hajib\'s Kutadgu Bilig. It is the ancestor of modern Uyghur and Uzbek.'} };
LANG_DATA['sga'].meta = { family:'Indo-European (Celtic, Goidelic)', speakers:'Extinct (~600-900 CE)', countries:'Ireland, Scotland (briefly Pictish areas)', official:'Early Irish kingdoms', script:'Latin (uncial) / Ogham (earlier)', description:{en:'Old Irish is the form of Irish from c. 600-900 CE, attested primarily in glosses on Latin manuscripts (Würzburg, Milan, St. Gall) and in legal texts. Famously complex morphologically, with initial consonant mutations, complex verb agreement, and an ergative-like distinction in some constructions.'} };

// === Phase 6 metadata ===
LANG_DATA['bsk'].meta = { family:'Language isolate', speakers:'~100K', countries:'Pakistan (Hunza, Yasin, Nagar)', official:'No (recognized regional)', script:'Perso-Arabic / Latin (academic)', description:{en:'Burushaski is a language isolate spoken in the Karakoram mountains of northern Pakistan. Despite over a century of comparative work, no convincing genetic relations to other languages have been established. It has 4 noun classes (human masculine, human feminine, count, mass) and a complex pronominal prefix system on verbs.'} };
LANG_DATA['yag'].meta = { family:'Iranian (Eastern)', speakers:'~13K', countries:'Tajikistan (Yaghnob Valley)', official:'No (recognized minority)', script:'Cyrillic / Latin', description:{en:'Yaghnobi is the only modern descendant of Sogdian, the Eastern Iranian lingua franca of the Silk Road for over 1,000 years. Spoken by descendants of Sogdian refugees who fled to the inaccessible Yaghnob Valley after the 8th-century Arab conquest. It is one of the most linguistically significant minority languages in the world.'} };
LANG_DATA['srn'].meta = { family:'English-based creole (Atlantic)', speakers:'~600K (L1) / ~3M (total)', countries:'Suriname, Netherlands diaspora', official:'Suriname (de facto national lingua franca, with Dutch as official)', script:'Latin', description:{en:'Sranan Tongo is the lingua franca of Suriname, an English-based creole with substantial Dutch, Portuguese, and African influences. It developed during the 17th-century plantation economy and serves as the inter-ethnic language of Suriname\'s diverse population (Creole, Indian, Javanese, Maroon, Indigenous, Chinese).'} };
LANG_DATA['kwk'].meta = { family:'Wakashan (Northern)', speakers:'~250 (severely endangered)', countries:'Canada (British Columbia coast)', official:'No (recognized aboriginal)', script:'Latin (with apostrophes for ejectives, x̱ for /x/, ƛ for /tɬ/)', description:{en:'Kwak\'wala is the principal Northern Wakashan language, spoken by the Kwakwaka\'wakw of British Columbia\'s central coast. It has an extraordinarily complex consonant inventory with ejectives (k\', t\'), uvulars, lateral affricates, and contrasting series. Famous for the elaborate potlatch ceremonies of its speakers.'} };
LANG_DATA['sad'].meta = { family:'Khoisan (proposed isolate or with Hadza)', speakers:'~60K', countries:'Tanzania (Kondoa District)', official:'No (recognized minority)', script:'Latin (with click letters ǀ ǁ ǂ ǃ)', description:{en:'Sandawe is a click language of central Tanzania, sometimes proposed to be related to the Khoekhoe family or grouped with Hadza, but generally considered an isolate. It has 4 phonemic click types and a 5-tone system, making it one of Africa\'s most phonologically complex languages.'} };
LANG_DATA['pcc'].meta = { family:'Kra-Dai (Tai, Northern)', speakers:'~3M', countries:'China (Guizhou, Yunnan)', official:'No (recognized minority)', script:'Latin (Buyei) / Chinese characters / Old Bouyei script', description:{en:'Bouyei (Buyei) is closely related to Northern Zhuang, with which it forms a dialect continuum. The Romanized Bouyei orthography uses tone letters (l, x, z, q, h, j) at syllable end to mark its 6-8 tones. It has a long literary tradition using Chinese-character-based scripts for ritual texts.'} };
LANG_DATA['iuu'].meta = { family:'Hmong-Mien (Mienic)', speakers:'~400K', countries:'China, Vietnam, Laos, Thailand, USA (refugee diaspora)', official:'No (recognized minority)', script:'Latin (Modified Roman)', description:{en:'Iu Mien is the principal Mienic (Yao-branch) language, spoken across the highlands of southern China and Southeast Asia. The Modified Roman script (developed in 1984) replaced multiple competing earlier orthographies. American Iu Mien refugees from Laos formed a significant community in California and Oregon.'} };
LANG_DATA['hui'].meta = { family:'Trans-New Guinea (Engan)', speakers:'~150K', countries:'Papua New Guinea (Hela Province)', official:'No (recognized regional)', script:'Latin', description:{en:'Huli is one of the largest Engan languages of the New Guinea highlands. Huli speakers are known for their elaborate wig traditions and the famous Huli Wigmen culture. It uses a base-15 numeral system, unusual among the world\'s languages.'} };
LANG_DATA['tkl'].meta = { family:'Austronesian (Polynesian, Ellicean)', speakers:'~2K', countries:'Tokelau, New Zealand diaspora', official:'Tokelau (with English)', script:'Latin', description:{en:'Tokelauan is the language of Tokelau, a New Zealand-administered territory of three small atolls. Closely related to Tuvaluan and Samoan, it has a long-vowel-marking macron orthography. Most speakers now live in New Zealand, where Tokelauan is taught in some schools.'} };
LANG_DATA['squ'].meta = { family:'Salishan (Coast Salish, Central)', speakers:'~10 fluent (severely endangered)', countries:'Canada (British Columbia coast around Squamish)', official:'No (recognized aboriginal)', script:'Latin (with diacritics, apostrophes for ejectives, ƛ for /tɬ/)', description:{en:'Squamish (Sḵwx̱wú7mesh sníchim) is a Salishan language with extreme phonological complexity — voiceless lateral affricates, ejectives, uvulars, pharyngeals, and a distinctive pharyngeal stop /ʕ̚/. The community runs immersion programs and Squamish-medium schools to revitalize the language.'} };
LANG_DATA['mga'].meta = { family:'Indo-European (Celtic, Goidelic)', speakers:'Extinct (~900-1200 CE)', countries:'Ireland, Scotland', official:'Medieval Irish kingdoms', script:'Latin (insular)', description:{en:'Middle Irish is the form of Irish from c. 900-1200 CE, between Old Irish and Early Modern Irish. It is the language of the great medieval Irish epics (Táin Bó Cúailnge in its surviving form, the Book of Leinster, the Yellow Book of Lecan). Verbs simplified considerably from Old Irish.'} };
LANG_DATA['hbo'].meta = { family:'Afro-Asiatic (Semitic, Northwest, Canaanite)', speakers:'Liturgical (revived as Modern Hebrew in 19th c.)', countries:'Ancient Israel/Judah (Levant)', official:'Ancient Israelite kingdoms; Jewish liturgy', script:'Paleo-Hebrew (early) → Hebrew (square script, post-exilic)', description:{en:'Biblical Hebrew is the form of Hebrew used in the Hebrew Bible (Tanakh), c. 1200-200 BCE. It has 7 vowel phonemes (with phonemic length distinctions in older stages), pharyngeals, ejectives or emphatics, and a verb system based on root-and-pattern morphology. Modern Hebrew was revived from Biblical Hebrew in the 19th century.'} };

// === Phase 7 metadata ===
LANG_DATA['mpt'].meta = { family:'Trans-New Guinea (Mountain Ok)', speakers:'~3.5K', countries:'Papua New Guinea (Telefomin area)', official:'No', script:'Latin', description:{en:'Mian is a Mountain Ok language of the Trans-New Guinea family, spoken in the rugged Star Mountains of Papua New Guinea. It has six gender classes assigned to nouns based partly on biological sex and partly on shape and function, an unusual system in linguistic typology.'} };
LANG_DATA['ygr'].meta = { family:'Trans-New Guinea (Eastern Highlands)', speakers:'~10K', countries:'Papua New Guinea (Eastern Highlands)', official:'No', script:'Latin', description:{en:'Yagaria is an Eastern Highlands language of Papua New Guinea, classified within the Kainantu-Goroka branch of Trans-New Guinea. It uses several distinct verb forms reflecting evidentiality and aspect, common in Highland Papuan languages.'} };
LANG_DATA['quz'].meta = { family:'Quechuan (Southern, Cuzco-Collao)', speakers:'~1.5M', countries:'Peru (Cusco region)', official:'Peru (co-official)', script:'Latin (Cusco-Collao standard)', description:{en:'Cusco Quechua is the prestige variety of Southern Quechua, native to the historic Inca capital. Distinguished from other Quechuan varieties by aspirated and ejective stops (kh, k\'), inherited from contact with Aymara. It is one of the official languages of Peru.'} };
LANG_DATA['quy'].meta = { family:'Quechuan (Southern, Chanka)', speakers:'~900K', countries:'Peru (Ayacucho region)', official:'Peru (co-official)', script:'Latin', description:{en:'Ayacucho Quechua (Chanka Quechua) is the principal Southern Quechua variety of central Peru. Unlike Cusco Quechua, it lacks aspirated and ejective stops, providing a "cleaner" phoneme inventory. Often considered the literary standard for Southern Quechua.'} };
// Shipibo-Conibo — Pano family, Peruvian Amazon.
LANG_DATA['shp'].meta = { family:'Pano', speakers:'~26K', countries:'Peru (Ucayali River basin)', official:'Peru (co-official with Spanish)', script:'Latin', description:'Shipibo-Conibo (Jonibo) is a Pano-family language of the Peruvian Amazon, with vibrant L1 transmission (>90% in many communities) and active literary production. Linguistically notable for its complex evidentiality system and the kené geometric design tradition encoded both visually (in textiles) and aurally (in songs). Speakers also call themselves Jonibo ("the people").', sources:[{type:'reference', title:'Glottolog: Shipibo-Conibo', url:'https://glottolog.org/resource/languoid/id/ship1254'}, {type:'reference', title:'Ethnologue: shp', url:'https://www.ethnologue.com/language/shp/'}, {type:'reference', title:'Valenzuela (2003) Transitivity in Shipibo-Konibo', url:'https://www.degruyter.com/'}] };
LANG_DATA['cab'].meta = { family:'Arawakan (Northern, with Carib lexical layer)', speakers:'~200K', countries:'Honduras, Belize, Guatemala, Nicaragua, USA diaspora', official:'Honduras (recognized minority)', script:'Latin', description:{en:'Garifuna is the language of the Garifuna people, descended from Carib-speaking native peoples and West African slaves who escaped to St. Vincent in the 17th century. Linguistically Arawakan, it has a substantial Carib lexical layer, particularly in male speech (the historical sex-based vocabulary distinction has now mostly leveled). UNESCO recognized Garifuna culture in 2001.'} };
LANG_DATA['crx'].meta = { family:'Na-Dené (Athabaskan, Northern)', speakers:'~2K', countries:'Canada (British Columbia interior)', official:'No (recognized aboriginal)', script:'Latin (with diacritics)', description:{en:'Carrier (Dakelh) is a Northern Athabaskan language native to the central interior of British Columbia. The name "Carrier" refers to the traditional practice of widows carrying their deceased husbands\' ashes in a pack. Like other Athabaskan languages, it has a complex tone system and ejective consonants.'} };
LANG_DATA['tsi'].meta = { family:'Tsimshianic (Maritime)', speakers:'~200', countries:'Canada (BC north coast), USA (Alaska)', official:'No (recognized aboriginal)', script:'Latin (with apostrophes for ejectives, ḵ for /q/)', description:{en:'Coast Tsimshian (Sm\'algyax) is a Tsimshianic language of the British Columbia and southeast Alaska coast. Like its Northwest Coast neighbors, it has a rich consonant system with ejectives (k\', t\', p\'), uvulars, and pharyngeal-like sounds. Major revitalization efforts include immersion schools at Lax Kw\'alaams.'} };
LANG_DATA['wbl'].meta = { family:'Iranian (Pamir)', speakers:'~58K', countries:'Tajikistan, Afghanistan, Pakistan, China (Xinjiang)', official:'No (recognized minority)', script:'Cyrillic / Latin / Arabic', description:{en:'Wakhi is a Pamir Iranian language of the high-altitude Wakhan Corridor. Speakers live above 2,500m in some of the most remote inhabited valleys on Earth. Like other Pamir languages, it preserves several archaic Iranian features lost in Persian.'} };
LANG_DATA['psi'].meta = { family:'Indo-Aryan (Dardic)', speakers:'~600K', countries:'Afghanistan (Kapisa, Laghman, Kunar)', official:'No (recognized minority)', script:'Perso-Arabic', description:{en:'Pashai (also called Pashayi) is a Dardic Indo-Aryan language of central Afghanistan. It is one of the most divergent Indo-Aryan languages, preserving several archaic features and showing extensive Iranian (Pashto, Persian) contact influence.'} };
LANG_DATA['bgq'].meta = { family:'Indo-Aryan (Western, Rajasthani)', speakers:'~5M', countries:'India (Rajasthan, Haryana, Punjab), Pakistan (Sindh)', official:'No (recognized regional)', script:'Devanagari', description:{en:'Bagri is a Rajasthani language closely related to Marwari, native to northern Rajasthan and adjoining areas. It shares much of its core vocabulary with Marwari but has distinct phonological features. Some classifications treat it as a Marwari dialect.'} };
LANG_DATA['ach'].meta = { family:'Nilo-Saharan (Western Nilotic, Luo)', speakers:'~1.5M', countries:'Uganda (north), South Sudan', official:'No (recognized regional)', script:'Latin', description:{en:'Acholi is a Western Nilotic language of northern Uganda and South Sudan, closely related to Lango and Alur (together forming the Acholi-Alur cluster). Acholi was the language of the Lord\'s Resistance Army conflict but also has rich oral literature traditions.'} };
LANG_DATA['rki'].meta = { family:'Sino-Tibetan (Burmish)', speakers:'~2.4M', countries:'Myanmar (Rakhine), Bangladesh (Chittagong Hill Tracts)', official:'No (regional)', script:'Burmese', description:{en:'Rakhine (Arakanese) is a Burmish language closely related to Burmese but with distinct phonology, including preservation of the medial /r/ that Burmese lost. Spoken in the coastal Rakhine State of Myanmar, it is the language of the historical Arakan Kingdom and the Rakhine people.'} };
// Hakha Chin (Lai) — Sino-Tibetan Kuki-Chin, ~125K, Chin State Myanmar + India.
LANG_DATA['cnh'].meta = { family:'Sino-Tibetan (Tibeto-Burman, Kuki-Chin, Central)', speakers:'~125K', countries:'Myanmar (Chin State — Hakha township), India (Mizoram); diaspora in USA (Indianapolis, Tulsa)', official:'Myanmar (recognized regional in Chin State); Hakha is the de facto Chin lingua franca', script:'Latin (Lai orthography, by Welsh missionaries 1900s)', description:{en:'Hakha Chin (Lai Holh) is the prestige and de facto lingua franca variety of the Chin (Kuki-Chin) languages, centred on Hakha town in Chin State, Myanmar. It serves as the cross-clan communication medium for ~50 distinct Chin-related communities. Tonal with three contrastive tones, complex verbal morphology including direct/inverse alignment. Notable for the large Chin refugee diaspora in Indianapolis (~25K) and Tulsa (~15K) following political persecution in Myanmar from the 1990s onward.',ja:'ハカ・チン語（Lai Holh）はチン諸語（クキ・チン）の威信形式であり事実上のリングア・フランカで、ミャンマーのチン州ハカ町を中心とする。約50の異なるチン系共同体間の氏族横断的な伝達手段として機能する。3つの対立する声調を持ち、複雑な動詞形態（直接／逆配置を含む）を有する。1990年代以降のミャンマーでの政治迫害を受けて、米インディアナポリス（約2.5万人）とタルサ（約1.5万人）に大規模なチン難民ディアスポラが形成されている。',ko:'하카 친어(Lai Holh)는 친 어군(쿠키-친) 언어의 위신형이자 사실상의 링구아 프랑카이며, 미얀마 친주 하카 마을을 중심으로 한다. 약 50개의 서로 다른 친계 공동체 간의 씨족 횡단적 의사소통 매개체로 기능한다. 3개의 대립 성조를 가지며, 직접/역배열을 포함한 복잡한 동사 형태를 가진다. 1990년대 이후 미얀마에서의 정치적 박해로 미국 인디애나폴리스(약 2.5만 명)와 털사(약 1.5만 명)에 대규모 친 난민 디아스포라가 형성되어 있다.',zh:'哈卡钦语（Lai Holh）是钦诸语（库基-钦）的威信形式和事实通用语，以缅甸钦邦哈卡镇为中心。作为约 50 个不同钦语系社区之间跨氏族交流的媒介。具有三声调对立，复杂的动词形态包括直接/反向配置。自 1990 年代以来因缅甸的政治迫害，在美国印第安纳波利斯（约 2.5 万人）和塔尔萨（约 1.5 万人）形成了大规模的钦族难民散居。',vi:'Tiếng Hakha Chin (Lai Holh) là biến thể uy tín và là tiếng giao tiếp chung trên thực tế của các ngôn ngữ Chin (Kuki-Chin), tập trung ở thị trấn Hakha thuộc bang Chin, Myanmar. Đóng vai trò trung gian giao tiếp giữa khoảng 50 cộng đồng Chin khác nhau. Có thanh điệu với ba thanh tương phản, hình thái động từ phức tạp bao gồm phối hợp trực tiếp/đảo ngược. Đáng chú ý vì có cộng đồng người Chin tị nạn lớn tại Indianapolis (~25 nghìn) và Tulsa (~15 nghìn) sau những đợt đàn áp chính trị tại Myanmar từ những năm 1990.',de:'Hakha-Chin (Lai Holh) ist die Prestige- und faktische Verkehrsvarietät der Chin- (Kuki-Chin-)Sprachen mit Zentrum in der Stadt Hakha im Chin-Staat Myanmars. Sie dient als Verständigungsmittel zwischen rund 50 unterschiedlichen Chin-verwandten Gemeinschaften. Tonal mit drei kontrastiven Tönen, komplexer Verbmorphologie einschließlich direkter/inverser Alignierung. Bemerkenswert ist die große Chin-Diaspora in Indianapolis (~25.000) und Tulsa (~15.000) infolge politischer Verfolgung in Myanmar seit den 1990er Jahren.',fr:'Le hakha chin (Lai Holh) est la variété de prestige et la lingua franca de fait des langues chin (kuki-chin), centrée sur la ville de Hakha dans l\'État Chin du Myanmar. Elle sert de moyen de communication entre une cinquantaine de communautés chin distinctes. Tonale avec trois tons contrastifs, morphologie verbale complexe incluant l\'alignement direct/inverse. Notable pour la grande diaspora de réfugiés chin à Indianapolis (~25 000) et Tulsa (~15 000) à la suite des persécutions politiques au Myanmar à partir des années 1990.'}, sources:[{type:'reference', title:'Glottolog: Hakha Chin', url:'https://glottolog.org/resource/languoid/id/haka1240'}, {type:'reference', title:'Ethnologue: cnh', url:'https://www.ethnologue.com/language/cnh/'}, {type:'reference', title:'King (2010) A Grammar of Hakha Lai', url:'https://www.degruyter.com/'}] };
LANG_DATA['kxm'].meta = { family:'Austroasiatic (Khmeric)', speakers:'~1.4M', countries:'Thailand (Surin, Sisaket, Buriram)', official:'No (recognized minority)', script:'Thai / Khmer', description:{en:'Northern Khmer (Khmer Surin) is the variety of Khmer spoken in northeastern Thailand by descendants of the medieval Khmer Empire. It diverged from Central Khmer through extensive Thai and Lao contact and shows distinctive phonological developments.'} };
LANG_DATA['xng'].meta = { family:'Mongolic', speakers:'Extinct (13th-15th c.)', countries:'Mongol Empire', official:'Mongol Empire (administrative)', script:'Uyghur-Mongolian / Phags-pa', description:{en:'Middle Mongol was the language of the Mongol Empire under Genghis Khan and his successors. Attested in the Secret History of the Mongols and Phags-pa script inscriptions, it is the ancestor of all modern Mongolic languages.'}, disambiguator:{en:'(Middle Mongolian, 13th-15th c.)',ja:'（中世モンゴル語、13-15世紀）',ko:'(중세 몽골어, 13-15세기)',zh:'（中世纪蒙古语，13-15世纪）'} };
LANG_DATA['ja_kg'].meta = { family:'Japonic (Kyushu)', speakers:'~1.6M', countries:'Japan (Kagoshima Prefecture)', official:'No (regional)', script:'Japanese (kanji + kana)', description:{en:'Kagoshima dialect (Satsugu) is a highly divergent Japanese dialect of southern Kyushu, traditionally so distinct from standard Japanese that it was reportedly used as a code by the Imperial Japanese Navy. It preserves archaic features and shows extensive vowel reduction.'} };
LANG_DATA['ja_sd'].meta = { family:'Japonic (Tohoku)', speakers:'~2.3M', countries:'Japan (Miyagi Prefecture)', official:'No (regional)', script:'Japanese (kanji + kana)', description:{en:'Sendai dialect is a Tohoku Japanese variety known for its zuzu-ben pronunciation that merges /i/ and /u/, voicing of intervocalic stops, and distinctive intonation. It is the most prominent dialect of the Tohoku region.'} };
LANG_DATA['ko_hg'].meta = { family:'Koreanic', speakers:'~3M', countries:'North Korea (Hamgyong), China (Yanbian)', official:'No (regional)', script:'Hangul', description:{en:'Hamgyong dialect is a northeastern Korean variety preserving pitch accent (lost in Seoul Korean) and many archaic vocabulary items. It forms the basis of the Korean spoken by the Korean diaspora in Russian Far East and Central Asia (Koryo-mar).'} };
LANG_DATA['ko_jl'].meta = { family:'Koreanic', speakers:'~5M', countries:'South Korea (Jeolla provinces)', official:'No (regional)', script:'Hangul', description:{en:'Jeolla dialect is the southwestern Korean variety, distinguished by its characteristic sentence-final endings and pitch patterns. It has played a significant role in Korean literature, music (pansori), and cuisine traditions.'} };
LANG_DATA['nan_pn'].meta = { family:'Sinitic (Min Nan)', speakers:'~500K', countries:'Malaysia (Penang), Medan area', official:'No', script:'Chinese characters / Latin', description:{en:'Penang Hokkien is a variety of Min Nan Chinese spoken in Penang and northern Malaysia. It diverged from mainland Hokkien through extensive Malay loanword borrowing and contact with Cantonese and English in the multicultural Straits Settlement.'}, parentCode:'nan' };
