LANG_DATA['fon'].meta = { family:'Niger-Congo (Volta-Niger, Gbe)', speakers:'~2.2M', countries:'Benin, Togo, Nigeria', official:'No (national language of Benin)', script:'Latin', description:{en:'Fon (Fɔ̀ngbè) is the principal language of southern Benin, spoken by the Fon people who founded the historical Kingdom of Dahomey. It is a tonal Gbe language closely related to Ewe and is an important source of Vodun religious tradition.'} };
LANG_DATA['kri'].meta = { family:'English-based creole', speakers:'~7M (incl. L2)', countries:'Sierra Leone', official:'No (de facto national)', script:'Latin', description:{en:'Krio is the English-based creole that serves as the lingua franca of Sierra Leone. It developed among Liberated Africans (formerly enslaved people) resettled in Freetown in the early 19th century, and incorporates significant Yoruba and other West African vocabulary.'} };
LANG_DATA['dag'].meta = { family:'Niger-Congo (Gur, Mabia)', speakers:'~1.2M', countries:'Ghana (Northern Region)', official:'No (recognized regional)', script:'Latin', description:{en:'Dagbani (Dagbanli) is the language of the Dagomba people of northern Ghana. It is a Mabia (Western Oti-Volta) language closely related to Mampruli and Nanun, and is the language of the historical Kingdom of Dagbon.'} };
LANG_DATA['xog'].meta = { family:'Atlantic-Congo (Bantu, Great Lakes)', speakers:'~3.4M', countries:'Uganda (Busoga)', official:'No (recognized regional)', script:'Latin', description:{en:'Soga (Lusoga) is a Great Lakes Bantu language closely related to Luganda, spoken in the Busoga region of southeastern Uganda. The Basoga people maintained a kingdom (Busoga) historically separate from but culturally connected to Buganda.'} };
