LANG_DATA['tcy'].meta = { family:'Dravidian (Southern)', speakers:'~1.85M', countries:'India (Karnataka, Kerala)', official:'No (recognized regional)', script:'Kannada / Tigalari (historical)', description:{en:'Tulu is a Dravidian language of the Tulu Nadu region of southwestern India (coastal Karnataka and northern Kerala). One of the five major Dravidian literary languages, with a rich oral tradition (Paddana epics) and the unique Tigalari script historically used for Sanskrit and Tulu manuscripts.'} };
LANG_DATA['haz'].meta = { family:'Iranian (Persian)', speakers:'~3.7M', countries:'Afghanistan (Hazarajat), Pakistan, Iran', official:'No (recognized regional)', script:'Perso-Arabic', description:{en:'Hazaragi is the variety of Persian spoken by the Hazara people of central Afghanistan. It diverges from Standard Dari in phonology (e.g., /b/→/w/), lexicon, and Mongolic/Turkic loanwords reflecting historical contact during the Mongol period.'} };
LANG_DATA['tly'].meta = { family:'Iranian (Northwestern)', speakers:'~900K', countries:'Azerbaijan, Iran (Gilan)', official:'No (recognized minority)', script:'Latin / Cyrillic / Perso-Arabic', description:{en:'Talysh (Tolışi) is a Northwestern Iranian language of the southwestern Caspian coast, related to Tati and the historical Median language. It is spoken in southern Azerbaijan and the Iranian Caspian provinces.'} };
LANG_DATA['kaa'].meta = { family:'Turkic (Kipchak)', speakers:'~600K', countries:'Uzbekistan (Karakalpakstan)', official:'Karakalpakstan (autonomous republic)', script:'Latin / Cyrillic', description:{en:'Karakalpak (Qaraqalpaqsha) is a Kipchak Turkic language closely related to Kazakh and Nogai, spoken in the autonomous Republic of Karakalpakstan in northwestern Uzbekistan. The Karakalpaks have maintained a distinct identity from the surrounding Uzbeks and Kazakhs.'} };
LANG_DATA['bej'].meta = { family:'Afro-Asiatic (Cushitic, North)', speakers:'~3M', countries:'Sudan, Eritrea, Egypt', official:'No (recognized regional)', script:'Arabic / Latin', description:{en:'Beja (Bidhaawyeet, "language of the Beja") is the only North Cushitic language and the most divergent within Cushitic. It is spoken by the Beja nomadic peoples of the Red Sea hills, descendants of the historical Blemmyes and Medjay of antiquity.'} };
LANG_DATA['tig'].meta = { family:'Afro-Asiatic (Semitic, Ethiopian)', speakers:'~1.5M', countries:'Eritrea (lowlands), Sudan', official:'Eritrea (recognized)', script:'Ge\'ez', description:{en:'Tigre is an Ethiopian Semitic language of the Eritrean lowlands, closely related to Tigrinya and Ge\'ez. The Tigre people are predominantly Muslim pastoralists, and their language preserves several archaic features lost in Tigrinya.'} };
