// === formType for hyphen-marked stems (Audit Task 103) =============
// Cells whose surface form starts or ends with a hyphen (or asterisk for
// reconstructed) are bound stems / roots, not free citation forms.
// Annotate them via wordEvidence.formType so the modal can show users
// the displayed form is a stem, not a standalone word.
//   'bound-stem'         — verb stem requiring suffix (Inuktitut, Iranian)
//   'reconstructed-root' — proto-language root (PIE, PR)
//   'agreement-stem'     — noun-class agreement form (Bantu)
const FORM_TYPE_OVERLAY = {
    iu:  { eat: 'bound-stem', drink: 'bound-stem', love: 'bound-stem' },
    // Audit Task 191: ine PIE — every cell with a *-prefixed surface is a reconstructed root.
    ine: { water:'reconstructed-root', fire:'reconstructed-root', sun:'reconstructed-root', moon:'reconstructed-root', mother:'reconstructed-root', father:'reconstructed-root', eat:'reconstructed-root', drink:'reconstructed-root', love:'reconstructed-root', heart:'reconstructed-root', tree:'reconstructed-root', house:'reconstructed-root', dog:'reconstructed-root', cat:'reconstructed-root', hand:'reconstructed-root', eye:'reconstructed-root', one:'reconstructed-root', good:'reconstructed-root' },
    // Audit Task 191: pry Proto-Ryukyuan — same convention.
    pry: { water:'reconstructed-root', fire:'reconstructed-root', sun:'reconstructed-root', moon:'reconstructed-root', mother:'reconstructed-root', father:'reconstructed-root', eat:'reconstructed-root', drink:'reconstructed-root', heart:'reconstructed-root', tree:'reconstructed-root', house:'reconstructed-root', dog:'reconstructed-root', cat:'reconstructed-root', hand:'reconstructed-root', eye:'reconstructed-root', one:'reconstructed-root', good:'reconstructed-root' },
    pjk: { water:'reconstructed-root', fire:'reconstructed-root', sun:'reconstructed-root', moon:'reconstructed-root', mother:'reconstructed-root', father:'reconstructed-root', eat:'reconstructed-root', drink:'reconstructed-root', heart:'reconstructed-root', tree:'reconstructed-root', house:'reconstructed-root', dog:'reconstructed-root', cat:'reconstructed-root', hand:'reconstructed-root', eye:'reconstructed-root', one:'reconstructed-root', good:'reconstructed-root' },
    ng:  { one: 'agreement-stem', good: 'agreement-stem' },
    kmb: { one: 'agreement-stem' },
    her: { one: 'agreement-stem', good: 'agreement-stem' },
    toi: { one: 'agreement-stem' },
    smg: { good: 'agreement-stem' },
    // Audit Task 205: hyphen-prefixed/suffixed surface cells flagging
    // bound-stem (Yukaghir/Aleut verb roots that require enclitic
    // person-marking) and Bantu noun-class agreement-stem (Kuanyama
    // numeral/adjective stems that take a class prefix).
    ykg: { eat: 'bound-stem', drink: 'bound-stem' },
    ale: { drink: 'bound-stem', love: 'bound-stem' },
    kj:  { one: 'agreement-stem', good: 'agreement-stem' },
    // Audit Task 207: Bantu agreement-stem (lue Luvale) + Mongolic bound-stem
    // (cmg Khalkha, mvf Mongghul) + Kiranti bound-stem (tdh Thulung).
    lue: { one: 'agreement-stem', good: 'agreement-stem' },
    cmg: { eat: 'bound-stem', drink: 'bound-stem' },
    mvf: { eat: 'bound-stem', drink: 'bound-stem', love: 'bound-stem', thanks: 'bound-stem' },
    tdh: { eat: 'bound-stem', drink: 'bound-stem' },
    xpr: { eat: 'bound-stem', drink: 'bound-stem' },
    xqa: { eat: 'bound-stem', drink: 'bound-stem' },
    bsk: { eat: 'bound-stem', heart: 'bound-stem', hand: 'bound-stem', eye: 'bound-stem' },
    wbl: { eat: 'bound-stem', drink: 'bound-stem' },
    psi: { eat: 'bound-stem', drink: 'bound-stem' },
    xsc: { heart: 'bound-stem' },
    sog: { drink: 'bound-stem' },
    otk: { eat: 'bound-stem', drink: 'bound-stem', love: 'bound-stem' },
    // Audit Task 104: lexical compound annotations (multiword surface forms
    // that are nonetheless a single lexical item — a single concept).
    vi:    { sun: 'compound', moon: 'compound', heart: 'compound' },           // mặt trời, mặt trăng, trái tim
    vi_c:  { sun: 'compound', moon: 'compound', heart: 'compound' },
    vi_s:  { sun: 'compound', moon: 'compound', heart: 'compound' },
    hmn:   { eye: 'compound' },                                                // qhov muag
    chr:   { moon: 'compound' },                                               // ᏅᏓ ᏒᏃᏱ
    lkt:   { moon: 'compound' },                                               // haŋhépi wí
    ty:    { tree: 'compound' },                                               // tumu rā'au
    rap:   { tree: 'compound' },                                               // tumu rākau
    mrq:   { tree: 'compound' },                                               // tumu kahi
    ace:   { sun: 'compound' },                                                // mata uroe
    bug:   { sun: 'compound' },                                                // mata esso
    bbc:   { sun: 'compound' },                                                // mata ni ari
    sas:   { tree: 'compound' },                                               // lolon kayu
    cho:   { moon: 'compound' },                                               // hashi ninak
    ljp:   { tree: 'compound' },                                               // batang kayu
    mos:   { one: 'compound' },                                                // a yɛmbɛr
    // Khasi (kha): article + noun pattern; whole form functions as the nominal
    kha:   { sun: 'compound', heart: 'compound', tree: 'compound', house: 'compound', dog: 'compound', cat: 'compound', hand: 'compound', eye: 'compound' },
    gor:   { sun: 'compound' },     // mata lo dulahu
    mak:   { sun: 'compound', tree: 'compound' },
    mtq:   { sun: 'compound', heart: 'compound' },
    tyz:   { sun: 'compound' },
    // Akha (ahk) writes most basic words as 2-syllable compounds; tone-bearing
    ahk:   { water: 'compound', sun: 'compound', moon: 'compound', heart: 'compound', tree: 'compound', dog: 'compound', hand: 'compound', eye: 'compound', one: 'compound', cat: 'compound' },
    nut:   { sun: 'compound' },
    kek:   { eye: 'compound' },
    sda:   { sun: 'compound' },
    // Audit Task 149 Batch 2: French creole "tree" = pyé bwa / pye dibwa (lit. "tree wood")
    crs:   { tree: 'compound' },
    gcf:   { tree: 'compound' },
};
for (const code of Object.keys(FORM_TYPE_OVERLAY)) {
    if (!LANG_DATA[code]) continue;
    if (!LANG_DATA[code].wordEvidence) LANG_DATA[code].wordEvidence = {};
    const wEv = LANG_DATA[code].wordEvidence;
    for (const concept of Object.keys(FORM_TYPE_OVERLAY[code])) {
        if (!wEv[concept]) wEv[concept] = { evidence: 'inferred' };
        if (!wEv[concept].formType) wEv[concept].formType = FORM_TYPE_OVERLAY[code][concept];
    }
}

